# Provider configurations for different regions
provider "aws" {
  alias  = "us_west"
  region = "us-west-2"
}

provider "aws" {
  alias  = "eu_central"
  region = "eu-central-1"
}

provider "aws" {
  region = "us-east-1" # Route53 is global but needs a default provider
}

# Random suffix for unique naming
resource "random_id" "suffix" {
  byte_length = 4
}

# US West Elastic Beanstalk Application (shared across environments)
resource "aws_elastic_beanstalk_application" "app_us_west" {
  provider = aws.us_west
  name     = "app-${random_id.suffix.hex}"
}

# US West Elastic Beanstalk Environment
