    name      = "InstanceType"
    value     = "t3.micro"
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "VPCId"
    value     = ""
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "Subnets"
    value     = ""
  }
}

# EU Central Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "app_eu_central" {
  provider = aws.eu_central
  name     = "app-${random_id.suffix.hex}"
}

# EU Central Elastic Beanstalk Environment
resource "aws_elastic_beanstalk_environment" "eu_central" {
  provider            = aws.eu_central
  name                = "eu_central"
  application         = aws_elastic_beanstalk_application.app_eu_central.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.0.7 running Corretto 17"

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "InstanceType"
    value     = "t3.micro"
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "VPCId"
    value     = ""
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "Subnets"
    value     = ""
  }
}

# Route53 Hosted Zone
resource "aws_route53_zone" "main" {
  name = "example.com"
}

# US West CNAME record
resource "aws_route53_record" "us_west" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "us-west.example.com"
  type    = "CNAME"
  ttl     = 300
  records = [aws_elastic_beanstalk_environment.us_west.cname]
}

# EU Central CNAME record
resource "aws_route53_record" "eu_central" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "eu-central.example.com"
  type    = "CNAME"
  ttl     = 300
  records = [aws_elastic_beanstalk_environment.eu_central.cname]
}

# Geolocation routing policy - US traffic to US West, Europe to EU Central, default to US West
resource "aws_route53_record" "geo_app" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "app.example.com"
  type    = "A"

  geolocation_routing_policy {
    country_codes = ["US", "CA", "MX"]
    continent_code = "NA"
  }

  set_identifier = "North-America-to-US-West"
  ttl            = 300
  records        = ["1.2.3.4"] # Placeholder - use alias to load balancer in production

  alias {
    name                   = aws_route53_record.us_west.fqdn
    zone_id                = aws_route53_record.us_west.zone_id
    evaluate_target_health = false
  }
}

resource "aws_route53_record" "geo_app_europe" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "app.example.com"
  type    = "A"

  geolocation_routing_policy {
    continent_code = "EU"
  }

  set_identifier = "Europe-to-EU-Central"
  ttl            = 300
  records        = ["1.2.3.4"] # Placeholder

  alias {
    name                   = aws_route53_record.eu_central.fqdn
    zone_id                = aws_route53_record.eu_central.zone_id
    evaluate_target_health = false
  }
}

resource "aws_route53_record" "geo_app_default" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "app.example.com"
  type    = "A"

  geolocation_routing_policy {}

  set_identifier = "Default-to-US-West"
  ttl            = 300
  records        = ["1.2.3.4"] # Placeholder

  alias {
    name                   = aws_route53_record.us_west.fqdn
    zone_id                = aws_route53_record.us_west.zone_id
    evaluate_target_health = false
  }
}
