        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for CodeBuild
resource "aws_iam_role_policy" "codebuild_policy" {
  name = "codebuild-policy-${random_id.suffix.hex}"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:PutObject",
          "s3:PutObjectAcl",
          "s3:PutObjectVersionAcl"
        ]
        Resource = "*"
      }
    ]
  })
}

# CodeBuild source bucket (S3)
resource "aws_s3_bucket" "source" {
  bucket = "codebuild-source-${random_id.suffix.hex}"
}

resource "aws_s3_bucket_public_access_block" "source" {
  bucket = aws_s3_bucket.source.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# CodeBuild project
resource "aws_codebuild_project" "example" {
  name          = "example-project-${random_id.suffix.hex}"
  description   = "Example CodeBuild project"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/standard:5.0"
    type            = "LINUX_CONTAINER"
    privileged_mode = false
  }

  source {
    type = "S3"
    location = aws_s3_bucket.source.bucket
  }
}

# Build batch configuration
resource "aws_codebuild_project_build_batch_config" "example" {
  project_id = aws_codebuild_project.example.id

  batch_timeout_in_minutes = 60
  combine_build_spec_from_phases = true
  service_role             = aws_iam_role.codebuild_role.arn

  restrictions {
    maximum_age_in_minutes = 60
    compute_types_allowed  = ["BUILD_GENERAL1_SMALL"]
  }
}

