  name                               = "example-bot-${random_id.bot_suffix.hex}"
  abort_statement {
    message {
      content    = "Sorry, I could not understand. Goodbye."
      content_type = "PlainText"
    }
  }

  intent {
    name = "BookTrip"

    slot {
      name         = "location"
      slot_type    = aws_lex_slot_type.example.name
      slot_constraint = "Required"
      priority     = 1
      message {
        content    = "What city would you like to visit?"
        content_type = "PlainText"
      }
    }

    slot {
      name         = "date"
      slot_type    = "AMAZON.DATE"
      slot_constraint = "Required"
      priority     = 2
      message {
        content    = "When would you like to travel?"
        content_type = "PlainText"
      }
    }

    fulfillment_activity {
      type = "ReturnIntent"
      code_hook {
        message_version = "1.0"
        uri             = "https://example.com/fulfillment"
      }
    }

    conclusion_statement {
      message {
        content    = "Thanks for booking your trip!"
        content_type = "PlainText"
      }
    }
  }

  clarification_prompt {
    max_attempts = 3
    message {
      content    = "Sorry, can you repeat that?"
      content_type = "PlainText"
    }
  }

  voice_id = "Joanna"

  process_behavior = "BUILD"

  depends_on = [aws_lex_slot_type.example]
}

resource "aws_lex_slot_type" "example" {
  name          = "City"
  version       = 1
  enumeration_value {
    name = "Seattle"
  }
  enumeration_value {
    name = "New York"
  }
  enumeration_value {
    name = "London"
  }
}
