resource "aws_lex_bot" "pizza_order" {
  name                        = "PizzaOrderBot-${random_id.suffix.hex}"
  description                 = "Pizza ordering bot with followup questions"
  abort_statement {
    message {
      content_type = "PlainText"
      content      = "Sorry, I couldn't process that. Goodbye!"
    }
  }
  create_version = true
  idle_session_ttl_in_seconds = 300

  intent {
    name = "OrderPizza"
    intent_version = "1"

    slot {
      name                  = "PizzaSize"
      slot_constraint       = "Required"
      slot_type             = "PizzaSize"
      value_elicitation_prompt {
        messages {
          content_type = "PlainText"
          content      = "What size pizza would you like? Small, medium, or large?"
        }
      }
    }

    slot {
      name                  = "PizzaTopping"
      slot_constraint       = "Required"
      slot_type             = "PizzaTopping"
      value_elicitation_prompt {
        messages {
          content_type = "PlainText"
          content      = "What toppings would you like on your pizza?"
        }
      }
    }

    slot {
      name                  = "DeliveryAddress"
      slot_constraint       = "Required"
      slot_type             = "AMAZON.PostalCode"
      value_elicitation_prompt {
        messages {
          content_type = "PlainText"
          content      = "What's the delivery address or zip code?"
        }
      }
    }

    fulfillment_activity {
      type = "ReturnLambda"
      code_hook {
        message_version = "1.0"
        uri             = "arn:aws:lambda:us-east-1:123456789012:function:PizzaOrderHandler"
      }
    }

    confirmation_prompt {
      messages {
        content_type = "PlainText"
        content      = "You want a {PizzaSize} pizza with {PizzaTopping} delivered to {DeliveryAddress}. Is that correct?"
      }
    }

    confirmation_response {
      messages {
        content_type = "PlainText"
        content      = "Great! Your pizza order has been placed. It'll be delivered soon!"
      }
    }

    denial_response {
      messages {
        content_type = "PlainText"
        content      = "No problem! Let me know if you want to try ordering again."
      }
    }
  }

  locale_configuration {
    locale       = "en_US"
    voice_settings {
      voice_id = "Joanna"
    }
  }
}

