  voice_id                           = "Joanna"

  locale_configuration {
    locale                = "en_US"
    voice_version         = "1"
    nlu_confidence_threshold = 0.20

    intent {
      name = "OrderPizza"

      slot {
        name = "PizzaSize"
        slot_constraint = "Required"
        slot_type = "AMAZON.Size"
        value_elicitation_prompt {
          messages {
            content_type = "PlainText"
            content      = "What size pizza would you like? Small, medium, or large?"
          }
        }
      }

      slot {
        name = "PizzaToppings"
        slot_constraint = "Optional"
        slot_type = "AMAZON.Food"
        value_elicitation_prompt {
          messages {
            content_type = "PlainText"
            content      = "Any toppings you'd like? Pepperoni, mushrooms, etc.?"
          }
        }
      }

      fulfillment_activity {
        type = "ReturnLambda"
        code_hook {
          message_version = "1.0"
          uri             = "arn:aws:lambda:us-east-1:123456789012:function:PizzaOrderHandler"
        }
      }
    }

    intent {
      name = "AMAZON.Cancel"
      priority = 1
    }

    intent {
      name = "AMAZON.Stop"
      priority = 2
    }
  }

  conclusion_statement {
    messages {
      content_type = "PlainText"
      content      = "Your pizza order has been placed successfully! It will be ready for pickup in about 20 minutes. Thank you for choosing Pizza Palace!"
    }
  }

  abort_statement {
    messages {
      content_type = "PlainText"
      content      = "Sorry, I couldn't process your request. Goodbye."
    }
  }
}
```

