```hcl
resource "random_id" "suffix" {
  byte_length = 4
}

resource "aws_lex_bot" "pizza_order_kids" {
  name                        = "PizzaOrderKidsBot-${random_id.suffix.hex}"
  description                 = "Fun pizza ordering bot designed for kids!"
  abort_statement {
    message {
      content    = "Oops! Let's try that again! 🧀🍕"
      content_type = "PlainText"
    }
  }
  idle_session_ttl_in_seconds = 300
  voice_id                    = "Joanna" # Friendly voice for kids

  intent {
    name = "OrderPizza"
    intent_version = "1"

    fulfillment_activity {
      type = "ReturnParameters"

      code_hook {
        message_version = "1.0"
        uri             = "AMAZON.Lambda"
      }
    }

    slot {
      name = "PizzaSize"
      slot_constraint = "Required"
      slot_type = "PizzaSizeType"
      priority = 1
      value_elicitation_prompt {
        message {
          content    = "Yay! What size pizza? Small, medium, or large? 🍕"
          content_type = "PlainText"
        }
      }
    }

    slot {
      name = "PizzaToppings"
      slot_constraint = "Optional"
      slot_type = "PizzaToppingType"
      priority = 2
      value_elicitation_prompt {
        message {
          content    = "What yummy toppings? Pepperoni, cheese, or veggies? 🧀🍄"
          content_type = "PlainText"
        }
      }
    }
  }

  clarification_prompt {
    max_attempts = 3
    message {
      content    = "Hmm, can you say that again? I'm listening! 😊"
      content_type = "PlainText"
    }
  }

  child_directed = true # Important for kids bot
}

# Sample slot types for kids pizza ordering
resource "aws_lex_slot_type" "pizza_size" {
  name          = "PizzaSizeType-${random_id.suffix.hex}"
  value_selection_strategy = "PICK_ONE"
  enumeration_value {
    name  = "Small"
    synonyms = ["small", "tiny", "little"]
  }
  enumeration_value {
    name  = "Medium"
    synonyms = ["medium", "normal", "regular"]
  }
  enumeration_value {
    name  = "Large"
    synonyms = ["large", "big", "huge"]
  }
}

resource "aws_lex_slot_type" "pizza_topping" {
  name          = "PizzaToppingType-${random_id.suffix.hex}"
  value_selection_strategy = "PICK_ONE"
  enumeration_value {
    name  = "Pepperoni"
    synonyms = ["pepperoni", "pep", "spicy"]
  }
  enumeration_value {
    name  = "Cheese"
    synonyms = ["cheese", "cheesy", "extra cheese"]
  }
  enumeration_value {
    name  = "Veggies"
    synonyms = ["veggies", "vegetables", "veggie"]
  }
}
```

