# Random suffix for unique naming
resource "random_id" "suffix" {
  byte_length = 4
}

# IAM role for Lambda execution
resource "aws_iam_role" "lambda_exec" {
  name = "pizza-order-bot-lambda-${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy attachment for Lambda basic execution
resource "aws_iam_role_policy_attachment" "lambda_basic" {
  role       = aws_iam_role.lambda_exec.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# Lambda function for pizza ordering logic
resource "aws_lambda_function" "pizza_order" {
  filename         = "pizza_order.zip"  # Assume you have this zip file locally
  function_name    = "pizza-order-bot-${random_id.suffix.hex}"
  role            = aws_iam_role.lambda_exec.arn
  handler         = "index.handler"
  runtime         = "nodejs18.x"
  timeout         = 30

  environment {
    variables = {
      PIZZA_TOPPINGS = "pepperoni,cheese,mushrooms"
    }
  }
}

# Permission for Lex to invoke Lambda
resource "aws_lambda_permission" "lex_invoke" {
  statement_id  = "AllowExecutionFromLex"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.pizza_order.function_name
  principal     = "lex.amazonaws.com"
}

# Lex Bot for Pizza Ordering
resource "aws_lex_bot" "pizza_order_bot" {
  name                               = "PizzaOrderBot-${random_id.suffix.hex}"
  description                        = "Pizza ordering chatbot"
  abort_statement {
    message {
      content    = "Sorry, I couldn't process that. Goodbye!"
      content_type = "PlainText"
    }
  }

  intent {
    name = "OrderPizzaIntent"
    fulfillment_activity {
      type = "LambdaFulfillment"
      code_hook {
        message_version = "1.0"
        uri             = aws_lambda_function.pizza_order.invoke_arn
      }
    }
    sample_utterances = [
      "I want to order a pizza",
      "Can I get a pizza",
      "Order pizza please",
      "I'd like a pizza"
    ]
    slot {
      name         = "PizzaSize"
      slot_type    = "AMAZON.Size"
      slot_constraint = "Required"
      priority     = 1
      value_elicitation_prompt {
        messages {
          content = "What size pizza would you like?"
          content_type = "PlainText"
        }
      }
    }
    slot {
      name         = "PizzaToppings"
      slot_type    = "AMAZON.Food"
      slot_constraint = "Optional"
      priority     = 2
      value_elicitation_prompt {
        messages {
          content = "What toppings would you like on your pizza?"
          content_type = "PlainText"
        }
      }
    }
  }

  locale_configuration {
    locale               = "en_US"
    voice_settings {
      voice_id = "Joanna"
    }
  }

  test_bot_alias {
    bot_alias_name = "TestAlias"
    bot_versions_tested {
      version = "$LATEST"
    }
  }
}

