    s3_backup_mode              = "AllDocuments"
    s3_backup_configuration {
      role_arn   = aws_iam_role.firehose_role.arn
      bucket_arn = aws_s3_bucket.firehose_backup.arn
      prefix     = "opensearch-failed/"
    }
  }

  depends_on = [aws_iam_role_policy_attachment.firehose_role_policy]
}

resource "aws_iam_role" "firehose_role" {
  name = "firehose-opensearch-role-${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose-opensearch-policy-${random_id.suffix.hex}"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.firehose_backup.arn,
          "${aws_s3_bucket.firehose_backup.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "aoss:APIAccessAll"
        ]
        Resource = [
          "arn:aws:aoss:us-west-2:123456789012:collection/my-collection",
          "arn:aws:aoss:us-west-2:123456789012:indexing/my-collection/my-indexing"
        ]
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "firehose_role_policy" {
  role       = aws_iam_role.firehose_role.name
  policy_arn = aws_iam_role_policy.firehose_policy.arn
}

resource "aws_s3_bucket" "firehose_backup" {
  bucket = "firehose-opensearch-backup-${random_id.suffix.hex}"
}

resource "aws_s3_bucket_server_side_encryption_configuration" "firehose_backup" {
  bucket = aws_s3_bucket.firehose_backup.bucket

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_s3_bucket_versioning" "firehose_backup" {
  bucket = aws_s3_bucket.firehose_backup.id
  versioning_configuration {
    status = "Enabled"
  }
}
