  http_endpoint_destination {
    endpoint_configuration {
      url = "https://aws-api.newrelic.com/firehose-v1?Api-Key=YOUR_NEW_RELIC_LICENSE_KEY&InsightsInsertKey=YOUR_NEW_RELIC_INSERT_KEY"
    }

    buffering_hints {
      interval_in_seconds = 60
      size_in_mbs         = 1
    }

    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = "/aws/kinesis/firehose/${random_id.suffix.hex}"
      log_stream_name = "S3Delivery"
    }

    processing_configuration {
      enabled = true

      processing_defaults {
        type = "Lambda"

        lambda_function_parameters {
          parameter_name  = "LambdaFunctionArn"
          parameter_value = "arn:aws:lambda:us-east-1:123456789012:function:my-processing-function"
        }
      }
    }

    request_configuration {
      content_encoding = "GZIP"
    }

    retry_options {
      duration_in_seconds = 300
    }

    s3_backup_mode = "FailedDataOnly"
  }

  server_side_encryption {
    key_arn           = "arn:aws:kms:us-east-1:123456789012:key/1234abcd-12ab-34cd-56ef-1234567890ab"
    key_type          = "AWS_OWNED"
    kms_key_arn       = "arn:aws:kms:us-east-1:123456789012:key/1234abcd-12ab-34cd-56ef-1234567890ab"
    role_arn          = "arn:aws:iam::123456789012:role/firehose-role"
    server_side_encryption_kms_key_id = "arn:aws:kms:us-east-1:123456789012:key/1234abcd-12ab-34cd-56ef-1234567890ab"
  }

  s3_configuration {
    bucket_arn = "arn:aws:s3:::your-backup-bucket"
    role_arn   = "arn:aws:iam::123456789012:role/firehose-delivery-role"
  }

  tags = {
    Environment = "test"
  }
}

resource "aws_cloudwatch_log_group" "firehose_logs" {
  name              = "/aws/kinesis/firehose/${random_id.suffix.hex}"
  retention_in_days = 14
}
