variable "cluster_name" {
  type = string
}

# VPC subnet IDs variable (user needs to provide these)
variable "subnet_ids" {
  type = list(string)
}

# Random suffix for unique naming
resource "random_id" "suffix" {
  byte_length = 4
}

# IAM role for EKS cluster
resource "aws_iam_role" "eks_cluster" {
  name = "${var.cluster_name}-eks-cluster-${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "eks.amazonaws.com"
      }
    }]
    Version = "2012-10-17"
  })
}

# Attach AmazonEKSClusterPolicy
resource "aws_iam_role_policy_attachment" "eks_cluster_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSClusterPolicy"
  role       = aws_iam_role.eks_cluster.name
}

# Attach AmazonEKSServicePolicy
resource "aws_iam_role_policy_attachment" "eks_service_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSServicePolicy"
  role       = aws_iam_role.eks_cluster.name
}

# EKS Cluster
resource "aws_eks_cluster" "main" {
  name     = "${var.cluster_name}-${random_id.suffix.hex}"
  role_arn = aws_iam_role.eks_cluster.arn
  vpc_config {
    subnet_ids              = var.subnet_ids
    security_group_ids      = []
    endpoint_private_access = false
    endpoint_public_access  = true
  }

  depends_on = [
    aws_iam_role_policy_attachment.eks_cluster_policy,
    aws_iam_role_policy_attachment.eks_service_policy,
  ]

  # Provisioner to configure kubectl after cluster creation
  provisioner "local-exec" {
    command = "aws eks update-kubeconfig --region us-west-2 --name ${self.name}"
  }

  # Provisioner to clean up kubeconfig on destroy
  provisioner "local-exec" {
    when    = destroy
    command = "kubectl config delete-context ${self.name} || true"
  }

  lifecycle {
    ignore_changes = [tags]
  }
}

