# IAM policy document for EKS pods to assume the role
data "aws_iam_policy_document" "example" {
  statement {
    actions = ["sts:AssumeRoleWithWebIdentity"]
    effect  = "Allow"

    condition {
      test     = "StringEquals"
      variable = "${replace(aws_iam_role.example.arn, "/^arn:[^:]+:iam::\d+:role/", "")}:sub"
      values   = ["example:example-sa"]
    }

    principals {
      type        = "Federated"
      identifiers = ["arn:aws:iam::${data.aws_caller_identity.current.account_id}:oidc-provider/oidc.eks.us-west-2.amazonaws.com/id/EXAMPLED539D4633E53DE1B716D3041E"]
    }
  }
}

data "aws_caller_identity" "current" {}

# IAM role for pod identity
