resource "random_id" "suffix" {
  byte_length = 4
}

# CloudGoat data storage bucket
resource "aws_s3_bucket" "cloudgoat" {
  bucket = "cloudgoat-${var.bucket_suffix}-${random_id.suffix.hex}"
}

resource "aws_s3_bucket_ownership_controls" "cloudgoat" {
  bucket = aws_s3_bucket.cloudgoat.id
  rule {
    object_ownership = "ObjectWriter"
  }
}

resource "aws_s3_bucket_acl" "cloudgoat" {
  bucket = aws_s3_bucket.cloudgoat.id
  acl    = "private"
}

# Web data storage bucket
resource "aws_s3_bucket" "web" {
  bucket = "web-${var.bucket_suffix}-${random_id.suffix.hex}"
}

resource "aws_s3_bucket_ownership_controls" "web" {
  bucket = aws_s3_bucket.web.id
  rule {
    object_ownership = "ObjectWriter"
  }
}

resource "aws_s3_bucket_public_access_block" "web" {
  bucket = aws_s3_bucket.web.id

  block_public_acls       = true
  block_public_policy     = false
  ignore_public_acls      = true
  restrict_public_buckets = true
}

resource "aws_s3_object" "order_data" {
  bucket = aws_s3_bucket.web.id
  key    = "order_data2.csv"
  source = "order_data2.csv"
}

resource "aws_s3_bucket_policy" "web" {
  bucket = aws_s3_bucket.web.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:PutObject"
        Resource  = "${aws_s3_bucket.web.arn}/*"
      }
    ]
  })
}

