resource "random_id" "suffix" {
  byte_length = 4
}

resource "random_password" "master" {
  length  = 16
  special = true
}

# Primary Redshift cluster in us-east-1
resource "aws_redshift_cluster" "primary" {
  provider = aws.us-east-1

  cluster_identifier = "redshift-primary-${random_id.suffix.hex}"
  database_name      = "dev"
  master_username    = "master"
  master_password    = random_password.master.result
  node_type          = "dc2.large"
  cluster_type       = "multi-node"
  number_of_nodes    = 2

  cluster_subnet_group_name = aws_redshift_subnet_group.primary.name
  vpc_security_group_ids    = [aws_security_group.redshift.id]

  skip_final_snapshot = true
}

# Subnet group for primary cluster (us-east-1)
resource "aws_redshift_subnet_group" "primary" {
  provider = aws.us-east-1

  name       = "redshift-primary-${random_id.suffix.hex}"
  subnet_ids = data.aws_subnets.us-east-1-private.ids
}

# Security group for Redshift
resource "aws_security_group" "redshift" {
  provider = aws.us-east-1

  name_prefix = "redshift-"
  vpc_id      = data.aws_vpc.main.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/8"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Data sources for us-east-1
data "aws_vpc" "main" {
  provider = aws.us-east-1
  default = true
}

data "aws_subnets" "us-east-1-private" {
  provider = aws.us-east-1
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.main.id]
  }
  filter {
    name   = "tag:Name"
    values = ["*private*"]
  }
}

# Cross-region snapshot copy rule for replication to us-east-2
resource "aws_redshift_cluster_snapshot_copy" "replication" {
  provider = aws.us-east-1

  destination_region     = "us-east-2"
  snapshot_copy_grant    = aws_kms_key.snapshot.arn
  cluster_identifier     = aws_redshift_cluster.primary.id
  retain_deletion_policy = "Retain"
}

# KMS key for snapshot encryption
resource "aws_kms_key" "snapshot" {
  provider = aws.us-east-1

  description             = "KMS key for Redshift snapshot replication"
  enable_key_rotation     = true
  deletion_window_in_days = 30
}

# IAM role for Redshift snapshot copy
resource "aws_iam_role" "redshift_snapshot_copy" {
  provider = aws.us-east-1

  name = "redshift-snapshot-copy-${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "redshift.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "redshift_snapshot_copy" {
  provider = aws.us-east-1

  name = "redshift-snapshot-copy-policy"
  role = aws_iam_role.redshift_snapshot_copy.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kms:Encrypt",
          "kms:Decrypt",
          "kms:ReEncrypt*",
          "kms:GenerateDataKey*",
          "kms:DescribeKey"
        ]
        Resource = aws_kms_key.snapshot.arn
      }
    ]
  })
}

# Providers configuration (required for multi-region)
provider "aws" {
  alias  = "us-east-1"
  region = "us-east-1"
}

provider "aws" {
  alias  = "us-east-2"
  region = "us-east-2"
}

provider "aws" {
  region = "us-east-1"
  default_tags {
    tags = {
      Environment = "test"
      ManagedBy   = "Terraform"
    }
  }
}

