}

# Latest Amazon Linux AMI (data source to get latest)
data "aws_ami" "amazon_linux" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["al2023-ami-*-x86_64"]
  }

  filter {
    name   = "virtualization-type"
    values = ["hvm"]
  }
}

# EC2 Instance 1 in private subnet 1
resource "aws_instance" "linux_1" {
  ami                    = data.aws_ami.amazon_linux.id
  instance_type          = "t3.micro"
  subnet_id              = aws_subnet.private_1.id
  vpc_security_group_ids = [aws_security_group.ec2_efs.id]
  iam_instance_profile   = aws_iam_instance_profile.ssm.name

  user_data = <<-EOF
              #!/bin/bash
              yum update -y
              yum install -y amazon-efs-utils
              mkdir /mnt/efs
              mount -t efs ${aws_efs_file_system.shared.id}:/ /mnt/efs
              echo "${aws_efs_file_system.shared.id}:/ /mnt/efs efs defaults,_netdev 0 0" >> /etc/fstab
              EOF

  tags = {
    Name = "linux-instance-1"
  }
}

# EC2 Instance 2 in private subnet 2
resource "aws_instance" "linux_2" {
  ami                    = data.aws_ami.amazon_linux.id
  instance_type          = "t3.micro"
  subnet_id              = aws_subnet.private_2.id
  vpc_security_group_ids = [aws_security_group.ec2_efs.id]
  iam_instance_profile   = aws_iam_instance_profile.ssm.name

  user_data = <<-EOF
              #!/bin/bash
              yum update -y
              yum install -y amazon-efs-utils
              mkdir /mnt/efs
              mount -t efs ${aws_efs_file_system.shared.id}:/ /mnt/efs
              echo "${aws_efs_file_system.shared.id}:/ /mnt/efs efs defaults,_netdev 0 0" >> /etc/fstab
              EOF

  tags = {
    Name = "linux-instance-2"
  }
}

# IAM Role and Policy for SSM and EFS access
resource "aws_iam_role" "ec2_role" {
  name = "ec2-efs-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
