resource "random_id" "suffix" {
  byte_length = 4
}

resource "aws_s3_bucket" "msk_logs" {
  bucket = "msk-cluster-logs-${random_id.suffix.hex}"
}

resource "aws_s3_bucket_server_side_encryption_configuration" "msk_logs" {
  bucket = aws_s3_bucket.msk_logs.bucket

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_msk_cluster" "example" {
  cluster_name           = "msk-cluster-${random_id.suffix.hex}"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type  = "kafka.m5.large"
    ebs_volume_size = 100    # GB
    client_subnets = ["subnet-0123456789abcdef0", "subnet-0123456789abcdef1", "subnet-0123456789abcdef2"] # Replace with your subnets
    security_groups = ["sg-0123456789abcdef0"] # Replace with your security group
  }

  vpc_config {
    subnet_ids         = ["subnet-0123456789abcdef0", "subnet-0123456789abcdef1", "subnet-0123456789abcdef2"] # Replace with your subnets
    security_group_ids = ["sg-0123456789abcdef0"] # Replace with your security group
  }

  logging_info {
    s3 {
      bucket              = aws_s3_bucket.msk_logs.bucket
      enabled             = true
      prefix              = "logs/"
    }
  }

  # Open to public for demo purposes - use IAM auth or VPC endpoints in production
  open_monitoring {
    prometheus {
      jmx_exporter {
        enabled_in_broker = true
      }
      node_exporter {
        enabled_in_broker = true
      }
    }
  }
}
```

**Note:** Before applying, replace the placeholder `subnet-` and `sg-` IDs with actual subnet IDs and security group IDs from your us-east-1 VPC. The cluster requires at least 2 subnets in different AZs.

