}

resource "aws_msk_cluster" "example" {
  cluster_name           = "msk-cluster-${random_id.suffix.hex}"
  kafka_version          = "3.5.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type  = "kafka.m5.large"
    client_subnets = ["subnet-12345678", "subnet-87654321", "subnet-abcdef12"] # Replace with your private subnet IDs in us-east-1
    security_groups = ["sg-12345678"] # Replace with your security group ID
  }

  vpc_config {
    subnet_ids         = ["subnet-12345678", "subnet-87654321", "subnet-abcdef12"] # Replace with your private subnet IDs in us-east-1
    security_group_ids = ["sg-12345678"] # Replace with your security group ID
  }

  # Enable public access for simplicity (use IAM auth in production)
  client_authentication {
    sasl {
      iam = { enabled = true }
    }
  }

  encryption_info {
    encryption_at_rest_kms_key_arn = "arn:aws:kms:us-east-1:111122223333:key/1234abcd-12ab-34cd-56ef-1234567890ab" # Replace with your KMS key ARN
  }
}

# Upload custom plugin (debezium.zip) to S3 first, then reference
resource "aws_s3_object" "debezium_plugin" {
  bucket = "your-bucket-name" # Replace with your S3 bucket name
  key    = "plugins/debezium.zip"
  source = "debezium.zip" # Local path to debezium.zip file
}

resource "aws_mskconnect_custom_plugin" "debezium" {
  name = "debezium-plugin-${random_id.suffix.hex}"

  content_type = "ZIPFILE"
  location {
    s3 {
      bucket_arn = aws_s3_object.debezium_plugin.bucket
      file_key   = aws_s3_object.debezium_plugin.key
    }
  }
}

resource "aws_mskconnect_connector" "example" {
  name = "debezium-connector-${random_id.suffix.hex}"

  connector_configuration = {
    "connector.class" = "io.debezium.connector.SourceConnector" # Example Debezium config
    "tasks.max"       = "1"
    "database.hostname" = "your-db-host" # Replace with your source DB details
    "database.port"     = "3306"
    "database.user"     = "debezium"
    "database.password" = "your-password"
    "database.server.id" = "12345"
    "database.server.name" = "dbserver1"
    "database.include.list" = "inventory"
    "kafka.api.key" = "" # Use IAM auth
    "kafka.api.secret" = ""
    "kafka.topic.prefix" = "dbserver1"
  }

  kafka_cluster {
    apache_kafka_cluster {
      bootstrap_servers = aws_msk_cluster.example.bootstrap_brokers_tls
      vpc {
        security_groups = [aws_msk_cluster.example.vpc_config[0].security_group_ids[0]]
        subnets         = aws_msk_cluster.example.vpc_config[0].subnet_ids
      }
    }
  }

  kafka_connect {
    custom_plugin {
      custom_plugin_arn = aws_mskconnect_custom_plugin.debezium.arn
    }
  }

  service_execution_role_arn = "arn:aws:iam::111122223333:role/MSKConnectServiceRole" # Replace with your MSK Connect service role ARN

  depends_on = [aws_msk_cluster.example]
}

