        subnets         = aws_msk_cluster.example.vpc_config[0].subnet_ids
      }
    }
  }

  kafka_connect {
    custom_plugin {
      custom_plugin_arn = aws_mskconnect_custom_plugin.debezium.arn
    }
  }

  service_execution_role_arn = "arn:aws:iam::111122223333:role/MSKConnectServiceRole" # Replace with your MSK Connect service role ARN

  depends_on = [aws_msk_cluster.example]
}
```

**Important Notes:**
1. Replace subnet IDs, security group IDs, KMS key ARN, S3 bucket name, and IAM role ARN with your actual values
2. Upload `debezium.zip` to your S3 bucket before running `terraform apply`
3. Update connector configuration with your actual source database details
4. Ensure subnets are private subnets in us-east-1 across 3+ AZs
5. Create an IAM service role for MSK Connect with necessary permissions
6. The connector config is a Debezium example - customize for your use case

