                           aws_subnet.subnet_az3.id]
            }
        }
    }

    kafka_cluster_client_authentication {
        authentication_type = "NONE"
    }

    kafka_cluster_encryption_in_transit {
        encryption_type = "PLAINTEXT"
    }

    plugin {
        custom_plugin {
            arn = aws_mskconnect_custom_plugin.example.arn
            revision = aws_mskconnect_custom_plugin.example.latest_revision
        }
    }

    service_execution_role_arn = aws_iam_role.aws_msk_connector_role.arn
}

response:
```hcl
# Random suffix for unique naming
resource "random_id" "suffix" {
  byte_length = 4
}

# CloudWatch Log Group for MSK
resource "aws_cloudwatch_log_group" "msk_logs" {
  name              = "/aws/msk/${random_id.suffix.hex}"
  retention_in_days = 7
}

# S3 Bucket for Firehose
resource "aws_s3_bucket" "firehose_bucket" {
  bucket = "msk-firehose-bucket-${random_id.suffix.hex}"
}

resource "aws_s3_bucket_ownership_controls" "firehose_bucket" {
  bucket = aws_s3_bucket.firehose_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "firehose_bucket" {
  depends_on = [aws_s3_bucket_ownership_controls.firehose_bucket]
  bucket     = aws_s3_bucket.firehose_bucket.id
  acl        = "private"
}

# Kinesis Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "msk_firehose" {
  name        = "msk-firehose-${random_id.suffix.hex}"
  destination = "s3"

  s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.firehose_bucket.arn
    prefix     = "firehose/"
  }
}

# IAM Role for Firehose
resource "aws_iam_role" "firehose_role" {
  name = "firehose-role-${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose-policy-${random_id.suffix.hex}"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "s3:PutObject",
          "s3:PutObjectAcl"
        ]
        Effect = "Allow"
        Resource = "${aws_s3_bucket.firehose_bucket.arn}/*"
      }
    ]
  })
}

# MSK Cluster with 3 brokers, encryption, and open monitoring
resource "aws_msk_cluster" "example" {
  cluster_name           = "msk-cluster-${random_id.suffix.hex}"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type  = "kafka.m5.large"
    ebs_volume_size = 1000    # 1TB per broker
    client_subnets = ["subnet-xxxxxxxx", "subnet-yyyyyyyy", "subnet-zzzzzzzz"] # Replace with your subnet IDs
    security_groups = ["sg-xxxxxxxx"] # Replace with your security group ID
  }

  encryption_info {
    encryption_at_rest {
      data_volume_kms_key_id = "arn:aws:kms:us-east-1:111122223333:key/1234abcd-12ab-34cd-56ef-1234567890ab" # Replace with your KMS key
    }
  }

  open_monitoring {
    prometheus {
      jmx_exporter {
        enabled_in_broker = true
      }
      node_exporter {
        enabled_in_broker = true
      }
    }
    cloudwatch_logs {
      enabled   = true
      log_group = aws_cloudwatch_log_group.msk_logs.name
    }
  }

  logging_info {
    cloudwatch_logs {
      enabled = true
      log_group = aws_cloudwatch_log_group.msk_logs.name
    }
    firehose {
      enabled = true
      delivery_stream = aws_kinesis_firehose_delivery_stream.msk_firehose.name
    }
  }

  # VPC configuration (replace with your VPC details)
  vpc_config {
    subnet_ids         = ["subnet-xxxxxxxx", "subnet-yyyyyyyy", "subnet-zzzzzzzz"]
    security_group_ids = ["sg-xxxxxxxx"]
  }
}

# S3 Bucket for MSK Connect Custom Plugin
resource "aws_s3_bucket" "msk_connect_plugin" {
  bucket = "msk-connect-plugin-${random_id.suffix.hex}"
}

resource "aws_s3_bucket_ownership_controls" "msk_connect_plugin" {
  bucket = aws_s3_bucket.msk_connect_plugin.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "msk_connect_plugin" {
  depends_on = [aws_s3_bucket_ownership_controls.msk_connect_plugin]
  bucket     = aws_s3_bucket.msk_connect_plugin.id
  acl        = "private"
}

# Upload Debezium custom plugin
resource "aws_s3_object" "debezium_plugin" {
  bucket = aws_s3_bucket.msk_connect_plugin.id
  key    = "debezium.zip"
  source = "debezium.zip" # Local path to debezium.zip file
}

# IAM Role for MSK Connect
resource "aws_iam_role" "msk_connect_role" {
  name = "msk-connect-role-${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kafkaconnect.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "msk_connect_policy" {
  name = "msk-connect-policy-${random_id.suffix.hex}"
  role = aws_iam_role.msk_connect_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kafka-cluster:Connect",
          "kafka-cluster:AlterCluster",
          "kafka-cluster:DescribeCluster"
        ]
        Resource = aws_msk_cluster.example.arn
      },
      {
        Effect = "Allow"
        Action = [
          "kafka:CreateGroup",
          "kafka:DeleteGroup",
          "kafka:DescribeGroup",
          "kafka:AlterGroup",
          "kafka:ReadData",
          "kafka:DescribeTopic",
          "kafka:WriteData",
          "kafka:CreateTopic",
          "kafka:DeleteTopic",
          "kafka-cluster:*"
        ]
        Resource = [
          aws_msk_cluster.example.arn,
          "${aws_msk_cluster.example.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.msk_connect_plugin.arn,
          "${aws_s3_bucket.msk_connect_plugin.arn}/*"
        ]
      }
    ]
  })
}

# MSK Connect Custom Plugin
resource "aws_mskconnect_custom_plugin" "debezium" {
  name       = "debezium-plugin-${random_id.suffix.hex}"
  description = "Debezium custom plugin"
  content_type = "ZIPFILE"

  s3_location {
    bucket_arn = aws_s3_bucket.msk_connect_plugin.arn
    file_key   = aws_s3_object.debezium_plugin.key
  }
}

# MSK Connect Worker Configuration
resource "aws_mskconnect_worker_configuration" "example" {
  name = "worker-config-${random_id.suffix.hex}"

  properties = {
    "client.payload.policy" = "ALWAYS"
  }
}

# MSK Connect Connector
resource "aws_mskconnect_connector" "debezium_connector" {
  connector_name = "debezium-connector-${random_id.suffix.hex}"
  kafka_cluster {
    apache_kafka_cluster {
      vpc_connection_arn = "arn:aws:kafkaconnect:us-east-1:111122223333:vpc-connection/vpc-xxxxxxxx" # Replace with your VPC connection ARN
      kafka_cluster_arn  = aws_msk_cluster.example.arn
      kafka_cluster_client_keystore = "NONE"
      kafka_cluster_client_certificate = "NONE"
      kafka_cluster_encryption_in_transit = "PLAINTEXT"
    }
  }
  service_execution_role_arn = aws_iam_role.msk_connect_role.arn
  worker_configuration {
    worker_configuration_arn = aws_mskconnect_worker_configuration.example.arn
  }
  capacity {
    provisioned_capacity {
      mku_count = 1
    }
  }
  connector_configuration = {
    "connector.class" = "io.debezium.connector.PostgresqlConnector"
    "database.hostname" = "your-postgres-host"
    "database.port" = "5432"
    "database.user" = "debezium"
    "database.password" = "password"
    "database.dbname" = "yourdb"
    "topic.prefix" = "debezium"
    "key.converter" = "org.apache.kafka.connect.json.JsonConverter"
    "value.converter" = "io.debezium.converters.BytesConverter"
    "value.converter.value.type" = "io.debezium.converters.JsonConverter"
    "value.converter.schemas.enable" = "false"
  }
  plugins {
    custom_plugin {
      custom_plugin_arn = aws_mskconnect_custom_plugin.debezium.arn
    }
  }
}
```

**Important Notes:**
1. Replace `subnet-xxxxxxxx`, `sg-xxxxxxxx`, and KMS key ARN with your actual VPC resources
2. Replace VPC connection ARN for MSK Connect with your actual VPC connection
3. Update PostgreSQL connection details in the connector configuration
4. Place `debezium.zip` file in your working directory before running `terraform apply`
5. Ensure proper IAM permissions and VPC connectivity between resources

