  tags = {
    Name = "redshift-vpc-${random_id.suffix.hex}"
  }
}

resource "aws_subnet" "subnet1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-2a"
  tags = {
    Name = "redshift-subnet-1-${random_id.suffix.hex}"
  }
}

resource "aws_subnet" "subnet2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-west-2b"
  tags = {
    Name = "redshift-subnet-2-${random_id.suffix.hex}"
  }
}

resource "aws_redshift_subnet_group" "main" {
  name       = "redshift-subnet-group-${random_id.suffix.hex}"
  subnet_ids = [aws_subnet.subnet1.id, aws_subnet.subnet2.id]

  tags = {
    Name = "redshift-subnet-group-${random_id.suffix.hex}"
  }
}

resource "random_password" "redshift" {
  length  = 16
  special = true
}

resource "aws_redshift_cluster" "example" {
  cluster_identifier = "redshift-cluster-${random_id.suffix.hex}"
  database_name      = "dev"
  master_username    = "masteruser"
  master_password    = random_password.redshift.result
  node_type          = "dc2.large"
  cluster_type       = "single-node"
  cluster_subnet_group_name = aws_redshift_subnet_group.main.name

  skip_final_snapshot = true
}

resource "aws_redshift_endpoint_access" "example" {
  cluster_identifier         = aws_redshift_cluster.example.id
  endpoint_name              = "redshift-endpoint-${random_id.suffix.hex}"
  subnet_group_name          = aws_redshift_subnet_group.main.name
  resource_owner             = "cluster"
}

