    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:GetObjectVersion"
        ]
        Resource = [
          "${aws_s3_bucket.autograder_artifacts.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "codecommit:GitPull"
        ]
        Resource = "*"
      }
    ]
  })
}

# CodeBuild project for autograder
resource "aws_codebuild_project" "autograder" {
  name          = "cs-autograder-${random_id.suffix.hex}"
  description   = "Autograder for CS class - runs student GitHub code"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "S3"
    name = "autograder-output"
    location = aws_s3_bucket.autograder_artifacts.bucket
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/standard:7.0"
    type            = "LINUX_CONTAINER"
    privileged_mode = true

    environment_variable {
      name  = "GITHUB_REPO"
      value = "https://github.com/your-org/student-submissions.git" # Replace with your GitHub repo
    }
    environment_variable {
      name  = "GRADE_OUTPUT_PATH"
      value = "/tmp/grades.json"
    }
  }

  source {
    type      = "GITHUB"
    location  = "https://github.com/your-org/student-submissions.git" # Replace with actual repo
    git_clone_depth = 1
  }

  # Sample buildspec for autograder (stored in repo root)
  buildspec = <<-EOF
    version: 0.2

    phases:
      install:
        commands:
          - echo "Installing Python and dependencies"
          - pip3 install pytest coverage

      pre_build:
        commands:
          - echo "Preparing test environment"
          - git clone $GITHUB_REPO student-code

      build:
        commands:
          - echo "Running autograder tests"
          - cd student-code
          - pytest tests/ --junitxml=/tmp/test-results.xml --cov=src --cov-report=xml:/tmp/coverage.xml
          - python3 generate_grades.py --output $GRADE_OUTPUT_PATH

      post_build:
        commands:
          - echo "Storing results"
          - aws s3 cp $GRADE_OUTPUT_PATH s3://${aws_s3_bucket.autograder_artifacts.bucket}/grades/
          - aws s3 cp /tmp/test-results.xml s3://${aws_s3_bucket.autograder_artifacts.bucket}/test-results/
          - aws s3 cp /tmp/coverage.xml s3://${aws_s3_bucket.autograder_artifacts.bucket}/coverage/

    reports:
      pytest-reports:
        files:
          - "/tmp/test-results.xml"
        base-directory: "/tmp"
    EOF
}

# Output the CodeBuild project name and S3 bucket for access
output "codebuild_project_name" {
  value = aws_codebuild_project.autograder.name
}

output "artifacts_bucket" {
  value = aws_s3_bucket.autograder_artifacts.bucket
}

output "codebuild_project_arn" {
  value = aws_codebuild_project.autograder.arn
}

