extracted_code:
# VPC for isolated CodeBuild environment
resource "aws_vpc" "autograder" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "autograder-vpc"
  }
}

# Private subnet for CodeBuild (no internet access)
resource "aws_subnet" "private" {
  vpc_id            = aws_vpc.autograder.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "autograder-private"
  }
}

# NAT Gateway subnet (for outbound GitHub access during build init only)
resource "aws_subnet" "public" {
  vpc_id            = aws_vpc.autograder.id
  cidr_block        = "10.0.100.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "autograder-public"
  }
}

# Internet Gateway
resource "aws_internet_gateway" "autograder" {
  vpc_id = aws_vpc.autograder.id

  tags = {
    Name = "autograder-igw"
  }
}

# Public route table for NAT
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.autograder.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.autograder.id
  }

  tags = {
    Name = "autograder-public-rt"
  }
}

resource "aws_route_table_association" "public" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public.id
}

# NAT Gateway for initial GitHub clone
resource "aws_eip" "nat" {
  domain = "vpc"
}

resource "aws_nat_gateway" "autograder" {
  allocation_id = aws_eip.nat.id
  subnet_id     = aws_subnet.public.id

  tags = {
    Name = "autograder-nat"
  }

  depends_on = [aws_internet_gateway.autograder]
}

# Private route table (limited outbound via NAT for GitHub only)
resource "aws_route_table" "private" {
  vpc_id = aws_vpc.autograder.id

  route {
    cidr_block     = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.autograder.id
  }

  tags = {
    Name = "autograder-private-rt"
  }
}

resource "aws_route_table_association" "private" {
  subnet_id      = aws_subnet.private.id
  route_table_id = aws_route_table.private.id
}

# Security Group - blocks all outbound except GitHub during build
resource "aws_security_group" "codebuild_sg" {
  name_prefix = "autograder-codebuild-"
  vpc_id      = aws_vpc.autograder.id

  # Allow SSH for debugging (optional)
  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  # No outbound internet rules - relies on VPC endpoints + NAT for GitHub only
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["10.0.0.0/16"] # VPC internal only
  }

  # Specific GitHub egress (CodeBuild service manages this during source fetch)
  egress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["192.30.252.0/22", "185.199.108.0/22", "140.82.112.0/20"] # GitHub IPs
  }

  tags = {
    Name = "autograder-codebuild-sg"
  }
}

# VPC endpoint for S3 (CodeBuild artifacts/results)
resource "aws_vpc_endpoint" "s3" {
  vpc_id            = aws_vpc.autograder.id
  service_name      = "com.amazonaws.us-east-1.s3"
  vpc_endpoint_type = "Gateway"
  route_table_ids   = [aws_route_table.private.id]
}

# VPC endpoint for CloudWatch Logs
resource "aws_vpc_endpoint" "logs" {
  vpc_id              = aws_vpc.autograder.id
  service_name        = "com.amazonaws.us-east-1.logs"
  vpc_endpoint_type   = "Interface"
  private_dns_enabled = true
  subnet_ids          = [aws_subnet.private.id]
  security_group_ids  = [aws_security_group.codebuild_sg.id]
}

# VPC endpoint for CodeBuild service
resource "aws_vpc_endpoint" "codebuild" {
  vpc_id              = aws_vpc.autograder.id
  service_name        = "com.amazonaws.us-east-1.codebuild"
  vpc_endpoint_type   = "Interface"
  private_dns_enabled = true
  subnet_ids          = [aws_subnet.private.id]
  security_group_ids  = [aws_security_group.codebuild_sg.id]
}

# CodeBuild Service Role
resource "aws_iam_role" "codebuild_role" {
  name = "autograder-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:us-east-1:*:log-group:/aws/codebuild/*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:PutObject",
          "s3:PutObjectAcl",
          "s3:DeleteObject"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "codebuild:BatchGetBuilds",
          "codebuild:StartBuild"
        ]
        Resource = "*"
      }
    ]
  })
}

# S3 bucket for source code and results (student submissions/results)
resource "aws_s3_bucket" "autograder" {
  bucket = "cs-autograder-${random_id.suffix.hex}"
}

resource "random_id" "suffix" {
  byte_length = 4
}

resource "aws_s3_bucket_versioning" "autograder" {
  bucket = aws_s3_bucket.autograder.id
  versioning_configuration {
    status = "Enabled"
  }
}

# CodeBuild Project
resource "aws_codebuild_project" "autograder" {
  name          = "cs-autograder-${random_id.suffix.hex}"
  description   = "CS Autograder - Isolated student code execution"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "S3"
    name = "autograder-artifacts"
    location = aws_s3_bucket.autograder.bucket
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/amazonlinux2-x86_64-standard:5.0"
    type            = "LINUX_CONTAINER"
    privileged_mode = true

    environment_variable {
      name  = "GITHUB_REPO"
      value = "https://github.com/yourorg/student-submissions" # Replace with actual repo
    }
    environment_variable {
      name  = "NO_INTERNET_TESTS"
      value = "true"
    }
  }

  source {
    type     = "S3"
    location = "${aws_s3_bucket.autograder.bucket}/student-submissions.zip"
    buildspec = <<EOF
version: 0.2

phases:
  install:
    commands:
      - echo "Installing test dependencies"
      - yum update -y
      - yum install -y git python3 gcc make
  pre_build:
    commands:
      - echo "Setting up isolated environment"
      - echo "Blocking all outbound except localhost" > /etc/hosts.allow
      - echo "ALL: all" >> /etc/hosts.deny
      - iptables -F OUTPUT
      - iptables -A OUTPUT -d 127.0.0.1 -j ACCEPT
      - iptables -A OUTPUT -m state --state ESTABLISHED,RELATED -j ACCEPT
      - iptables -P OUTPUT DROP
  build:
    commands:
      - echo "Running student tests..."
      - python3 -m pytest tests/ --junitxml=results.xml -v
      - echo "Test results saved"
  post_build:
    commands:
      - echo "Uploading results"
      - aws s3 cp results.xml s3://${aws_s3_bucket.autograder.bucket}/results/
artifacts:
  files:
    - results.xml
    - test-results/**/*
EOF
  }

  vpc_config {
    vpc_id             = aws_vpc.autograder.id
    subnet_ids         = [aws_subnet.private.id]
    security_group_ids = [aws_security_group.codebuild_sg.id]
  }

  tags = {
    Name = "cs-autograder"
  }
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_s3_bucket" "artifact_bucket" {
  bucket_prefix = "artifact-bucket-"
}

resource "aws_codebuild_project" "autograder_build" {
  name         = "autograder_build"
  service_role = aws_iam_role.autograder_build_role.arn

  artifacts {
    type     = "S3"
    location = aws_s3_bucket.artifact_bucket.arn
    name     = "results.zip" # include this
  }

  environment { # arguments required, exact value not specified
    compute_type = "BUILD_GENERAL1_SMALL"
    image        = "aws/codebuild/standard:7.0-24.10.29"
    type         = "LINUX_CONTAINER"
  }

  source {
    type            = "GITHUB"
    git_clone_depth = 1 # good to have, not required
    location        = "github.com/source-location"
  }

  vpc_config {
    vpc_id             = aws_vpc.autograder_vpc.id
    subnets            = [aws_subnet.autograder_vpc_subnet.id]
    security_group_ids = [aws_security_group.autograder_vpc_securitygroup.id]
  }
}

resource "aws_vpc" "autograder_vpc" {
  cidr_block = "10.0.0.0/16" # extra value not specified
}

resource "aws_subnet" "autograder_vpc_subnet" {
  vpc_id     = aws_vpc.autograder_vpc.id
  cidr_block = "10.0.0.0/24" # include this
}

resource "aws_security_group" "autograder_vpc_securitygroup" {
  vpc_id = aws_vpc.autograder_vpc.id
}

resource "aws_iam_role" "autograder_build_role" {
  assume_role_policy = data.aws_iam_policy_document.autograder_build_policy_assume.json
}

data "aws_iam_policy_document" "autograder_build_policy_assume" {
  statement {
    actions = ["sts:AssumeRole"]

    principals {
      type        = "Service"
      identifiers = ["codebuild.amazonaws.com"]
    }
  }
}

data "aws_iam_policy_document" "autograder_build_policy" {
  statement {
    effect = "Allow"
    actions = [
      "ec2:DescribeSubnets",
      "ec2:DescribeSecurityGroups",
      "ec2:DescribeVpcs"
    ]
    resources = [
      "*"
    ]
  }

  statement {
    effect  = "Allow"
    actions = ["s3:*"]
    resources = [
      aws_s3_bucket.artifact_bucket.arn,
      "${aws_s3_bucket.artifact_bucket.arn}/*",
    ]
  }
}

resource "aws_iam_policy" "autograder_build_policy" {
  name        = "lambda_policy"
  description = "Grants permissions to Lambda to describe vpc, subnet, security group"

  policy = data.aws_iam_policy_document.autograder_build_policy.json
}

resource "aws_iam_role_policy_attachment" "lambda_policy_attach" {
  role       = aws_iam_role.autograder_build_role.name
  policy_arn = aws_iam_policy.autograder_build_policy.arn
}

