resource "aws_codebuild_project" "autograder" {
  name          = "cs-autograder-${random_id.suffix.hex}"
  service_role  = aws_iam_role.codebuild_role.arn
  build_timeout = 300

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/amazonlinux2-x86_64-standard:5.0"
    type            = "LINUX_CONTAINER"
    privileged_mode = false

    environment_variable {
      name  = "S3_BUCKET"
      value = aws_s3_bucket.autograder.bucket
    }
  }

  source {
    type = "NO_SOURCE"
    # Trigger manually or via EventBridge/Lambda
  }

  vpc_config {
    vpc_id             = aws_vpc.autograder.id
    subnet_ids         = aws_subnet.private[*].id
    security_group_ids = [aws_security_group.codebuild.id]
  }

  # Sample buildspec - downloads student code from S3, runs tests, uploads results
  buildspec = <<-EOF
    version: 0.2

    phases:
      install:
        commands:
          - echo Installing dependencies...
          - yum update -y
          - yum install -y git python3 gcc make

      pre_build:
        commands:
          - echo Downloading student submission from S3...
          - aws s3 cp s3://$S3_BUCKET/submissions/$CODEBUILD_BUILD_ID.tar.gz /tmp/submission.tar.gz
          - tar -xzf /tmp/submission.tar.gz -C /tmp/
          - echo Student code extracted to /tmp/

      build:
        commands:
          - echo Running autograder tests...
          - cd /tmp/student-code
          - chmod +x run_tests.sh
          - timeout 300 ./run_tests.sh > /tmp/results.txt 2>&1 || true

      post_build:
        commands:
          - echo Uploading results to S3...
          - aws s3 cp /tmp/results.txt s3://$S3_BUCKET/results/$CODEBUILD_BUILD_ID-results.txt
          - aws s3 cp /tmp/test-output/ s3://$S3_BUCKET/results/$CODEBUILD_BUILD_ID/ --recursive
    EOF
}

