```hcl
# VPC with private subnets (no internet access)
resource "aws_vpc" "autograder" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "autograder-vpc"
  }
}

resource "aws_subnet" "private" {
  count = 2

  vpc_id            = aws_vpc.autograder.id
  cidr_block        = "10.0.${count.index + 1}.0/24"
  availability_zone = element(data.aws_availability_zones.available.names, count.index)

  tags = {
    Name = "autograder-private-${count.index + 1}"
  }
}

data "aws_availability_zones" "available" {}

# S3 bucket for storing student submissions and results (no public access)
resource "aws_s3_bucket" "autograder" {
  bucket = "cs-autograder-${random_id.suffix.hex}"
}

resource "aws_s3_bucket_public_access_block" "autograder" {
  bucket = aws_s3_bucket.autograder.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

resource "aws_s3_bucket_versioning" "autograder" {
  bucket = aws_s3_bucket.autograder.id
  versioning_configuration {
    status = "Enabled"
  }
}

# IAM role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "autograder-codebuild-role-${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for CodeBuild to access S3 and run in VPC
resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:GetObjectVersion"
        ]
        Resource = [
          "${aws_s3_bucket.autograder.arn}/*"
        ]
      }
    ]
  })
}

# CodeBuild project - runs in private VPC subnets (no internet)
resource "aws_codebuild_project" "autograder" {
  name          = "cs-autograder-${random_id.suffix.hex}"
  service_role  = aws_iam_role.codebuild_role.arn
  build_timeout = 300

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/amazonlinux2-x86_64-standard:5.0"
    type            = "LINUX_CONTAINER"
    privileged_mode = false

    environment_variable {
      name  = "S3_BUCKET"
      value = aws_s3_bucket.autograder.bucket
    }
  }

  source {
    type = "NO_SOURCE"
    # Trigger manually or via EventBridge/Lambda
  }

  vpc_config {
    vpc_id             = aws_vpc.autograder.id
    subnet_ids         = aws_subnet.private[*].id
    security_group_ids = [aws_security_group.codebuild.id]
  }

  # Sample buildspec - downloads student code from S3, runs tests, uploads results
  buildspec = <<-EOF
    version: 0.2

    phases:
      install:
        commands:
          - echo Installing dependencies...
          - yum update -y
          - yum install -y git python3 gcc make

      pre_build:
        commands:
          - echo Downloading student submission from S3...
          - aws s3 cp s3://$S3_BUCKET/submissions/$CODEBUILD_BUILD_ID.tar.gz /tmp/submission.tar.gz
          - tar -xzf /tmp/submission.tar.gz -C /tmp/
          - echo Student code extracted to /tmp/

      build:
        commands:
          - echo Running autograder tests...
          - cd /tmp/student-code
          - chmod +x run_tests.sh
          - timeout 300 ./run_tests.sh > /tmp/results.txt 2>&1 || true

      post_build:
        commands:
          - echo Uploading results to S3...
          - aws s3 cp /tmp/results.txt s3://$S3_BUCKET/results/$CODEBUILD_BUILD_ID-results.txt
          - aws s3 cp /tmp/test-output/ s3://$S3_BUCKET/results/$CODEBUILD_BUILD_ID/ --recursive
    EOF
}

# Security group for CodeBuild (no outbound internet access)
resource "aws_security_group" "codebuild" {
  name_prefix = "autograder-codebuild-"
  vpc_id      = aws_vpc.autograder.id

  egress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Only VPC internal traffic
  }

  tags = {
    Name = "autograder-codebuild-sg"
  }
}

# Random suffix for unique naming
resource "random_id" "suffix" {
  byte_length = 4
}

# Outputs
output "s3_bucket_name" {
  value = aws_s3_bucket.autograder.bucket
}

output "codebuild_project_name" {
  value = aws_codebuild_project.autograder.name
}

output "vpc_id" {
  value = aws_vpc.autograder.id
}
```

This configuration creates a secure autograder infrastructure:

1. **Private VPC** with isolated subnets (no internet gateway/NAT)
2. **S3 bucket** for student submissions/results (locked down, no public access)
3. **CodeBuild project** running in private subnets with no internet access
4. **Custom security group** blocks all external internet traffic
5. **Sample buildspec** downloads student code from S3, runs tests in isolation, uploads results
6. **IAM roles** with least-privilege access

**Usage**: 
- Upload student GitHub repos as tar.gz to `s3://bucket/submissions/<build-id>.tar.gz`
- Trigger CodeBuild manually or via EventBridge
- Results appear in `s3://bucket/results/<build-id>/`

The environment is completely air-gapped from the internet, ensuring student code cannot access external resources.

