import json
import boto3
import urllib.parse
import uuid

s3 = boto3.client('s3')

def lambda_handler(event, context):
    try:
        body = json.loads(event['body'])
        bucket = '${aws_s3_bucket.cat_pics.bucket}'
        key = f"cats/{str(uuid.uuid4())}-{body['filename']}"

        s3.put_object(
            Bucket=bucket,
            Key=key,
            Body=base64.b64decode(body['image_data']),
            ContentType=body['content_type']
