import json
import boto3
import random
import urllib.parse

s3 = boto3.client('s3')

def lambda_handler(event, context):
    try:
        bucket = '${aws_s3_bucket.cat_pics.bucket}'
        objects = s3.list_objects_v2(Bucket=bucket, Prefix='cats/')

        if 'Contents' not in objects or len(objects['Contents']) == 0:
            return {
                'statusCode': 404,
                'body': json.dumps({'error': 'No cat pictures available'})
            }

        random_obj = random.choice(objects['Contents'])
        key = random_obj['Key']

        url = s3.generate_presigned_url(
            'get_object',
            Params={'Bucket': bucket, 'Key': key},
            ExpiresIn=3600
        )

        return {
            'statusCode': 200,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({'url': url, 'key': key})
        }
    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps({'error': str(e)})
        }
EOF
    filename = "serve_handler.py"
  }
}

