  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "lambda_s3_list" {
  name = "s3-list-policy-${random_id.suffix.hex}"
  role = aws_iam_role.lambda_serve_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.cat_pics.arn,
          "${aws_s3_bucket.cat_pics.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      }
    ]
  })
}

data "archive_file" "lambda_serve" {
  type        = "zip"
  output_path = "/tmp/serve_handler.zip"

  source {
    content = <<EOF
import json
import boto3
import random
import urllib.parse

s3 = boto3.client('s3')

def lambda_handler(event, context):
    try:
        bucket = '${aws_s3_bucket.cat_pics.bucket}'
        objects = s3.list_objects_v2(Bucket=bucket, Prefix='cats/')

        if 'Contents' not in objects or len(objects['Contents']) == 0:
            return {
                'statusCode': 404,
                'body': json.dumps({'error': 'No cat pictures available'})
            }

        random_obj = random.choice(objects['Contents'])
        key = random_obj['Key']

        url = s3.generate_presigned_url(
            'get_object',
            Params={'Bucket': bucket, 'Key': key},
            ExpiresIn=3600
        )

        return {
            'statusCode': 200,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({'url': url, 'key': key})
        }
    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps({'error': str(e)})
        }
EOF
    filename = "serve_handler.py"
  }
}

resource "aws_lambda_function" "serve_handler" {
  filename         = data.archive_file.lambda_serve.output_path
  function_name    = "cat-serve-handler-${random_id.suffix.hex}"
  role             = aws_iam_role.lambda_serve_role.arn
  handler          = "serve_handler.lambda_handler"
  source_code_hash = data.archive_file.lambda_serve.output_base64sha256
  runtime          = "python3.9"
  timeout          = 30
}

# API Gateway
resource "aws_apigatewayv2_api" "cat_api" {
  name          = "cat-api-${random_id.suffix.hex}"
  protocol_type = "HTTP"
}

resource "aws_apigatewayv2_stage" "cat_stage" {
  api_id      = aws_apigatewayv2_api.cat_api.id
  name        = "prod"
  auto_deploy = true
}

# Integration for upload endpoint
resource "aws_apigatewayv2_integration" "upload_integration" {
  api_id             = aws_apigatewayv2_api.cat_api.id
  integration_type   = "AWS_PROXY"
  integration_uri    = aws_lambda_function.upload_handler.invoke_arn
  integration_method = "POST"
}

# Integration for random cat endpoint
resource "aws_apigatewayv2_integration" "serve_integration" {
  api_id             = aws_apigatewayv2_api.cat_api.id
  integration_type   = "AWS_PROXY"
  integration_uri    = aws_lambda_function.serve_handler.invoke_arn
  integration_method = "GET"
}

# Routes
resource "aws_apigatewayv2_route" "upload_route" {
  api_id    = aws_apigatewayv2_api.cat_api.id
  route_key = "POST /upload"
  target    = "integrations/${aws_apigatewayv2_integration.upload_integration.id}"
}

resource "aws_apigatewayv2_route" "serve_route" {
  api_id    = aws_apigatewayv2_api.cat_api.id
  route_key = "GET /random"
  target    = "integrations/${aws_apigatewayv2_integration.serve_integration.id}"
}

# Lambda permissions
resource "aws_lambda_permission" "upload_api" {
  statement_id  = "AllowAPIGatewayInvoke"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.upload_handler.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_apigatewayv2_api.cat_api.execution_arn}/*"
}

resource "aws_lambda_permission" "serve_api" {
  statement_id  = "AllowAPIGatewayInvoke"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.serve_handler.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_apigatewayv2_api.cat_api.execution_arn}/*"
}

# CORS for serve route
resource "aws_apigatewayv2_route" "cors_options" {
  api_id    = aws_apigatewayv2_api.cat_api.id
  route_key = "OPTIONS /{proxy+}"
  target    = "integrations/${aws_apigatewayv2_integration.serve_integration.id}"
}

# Output the API endpoint
output "api_endpoint" {
  value = aws_apigatewayv2_stage.cat_stage.invoke_url
}

output "s3_bucket_name" {
  value = aws_s3_bucket.cat_pics.bucket
}
```

This Terraform configuration creates a complete cat picture service with:

1. **S3 Bucket** - Stores all uploaded cat pictures
2. **Upload Lambda** (`POST /upload`) - Accepts base64-encoded image data and saves to S3
3. **Serve Lambda** (`GET /random`) - Returns a random cat picture with a presigned S3 URL
4. **API Gateway** - HTTP API with CORS support
5. **IAM Roles** - Proper permissions for Lambda to S3 access

**Usage:**
- `POST /upload` with JSON body: `{"filename": "cat.jpg", "image_data": "base64...", "content_type": "image/jpeg"}`
- `GET /random` returns JSON with presigned URL to a random cat picture

Run `terraform apply` and use the output `api_endpoint` to access your cat picture service!

