  rest_api_id             = aws_api_gateway_rest_api.cat_api.id
  resource_id             = aws_api_gateway_resource.cats.id
  http_method             = aws_api_gateway_method.get_random_cat.http_method
  integration_http_method = "POST"
  type                    = "AWS_PROXY"
  uri                     = aws_lambda_function.cat_service.invoke_arn
}

# API Gateway integration for specific cat
resource "aws_api_gateway_integration" "get_cat_by_id" {
  rest_api_id             = aws_api_gateway_rest_api.cat_api.id
  resource_id             = aws_api_gateway_resource.cat_id.id
  http_method             = aws_api_gateway_method.get_cat_by_id.http_method
  integration_http_method = "POST"
  type                    = "AWS_PROXY"
  uri                     = aws_lambda_function.cat_service.invoke_arn
}

# Deploy API
resource "aws_api_gateway_deployment" "cat_api_deployment" {
  depends_on = [
    aws_api_gateway_integration.upload_cat,
    aws_api_gateway_integration.get_random_cat,
    aws_api_gateway_integration.get_cat_by_id,
  ]

  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  stage_name  = "prod"
}
```

**Note:** This configuration assumes you have a `cat_service.zip` file containing the Lambda function code. The Lambda should handle:
- `POST /cats` - Upload cat picture to S3 and save metadata to DynamoDB
- `GET /cats` - Return random cat picture URL from DynamoDB
- `GET /cats/{catId}` - Return specific cat picture URL

