```hcl
# Random suffix for unique resource names
resource "random_id" "suffix" {
  byte_length = 4
}

# S3 bucket for video content with public access blocked at bucket level
resource "aws_s3_bucket" "video_content" {
  bucket = "video-streaming-${random_id.suffix.hex}"
}

resource "aws_s3_bucket_ownership_controls" "video_content" {
  bucket = aws_s3_bucket.video_content.id

  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "video_content" {
  depends_on = [aws_s3_bucket_ownership_controls.video_content]

  bucket = aws_s3_bucket.video_content.id
  acl    = "private"
}

# Bucket policy to allow CloudFront access via OAI
resource "aws_s3_bucket_policy" "video_content" {
  bucket = aws_s3_bucket.video_content.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "AllowCloudFrontAccess"
        Effect    = "Allow"
        Principal = {
          AWS = aws_cloudfront_origin_access_identity.video_oai.iam_arn
        }
        Action   = "s3:GetObject"
        Resource = "${aws_s3_bucket.video_content.arn}/*"
      }
    ]
  })
}

# Enable versioning and server-side encryption
resource "aws_s3_bucket_versioning" "video_content" {
  bucket = aws_s3_bucket.video_content.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "video_content" {
  bucket = aws_s3_bucket.video_content.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# CloudFront Origin Access Identity for secure S3 access
resource "aws_cloudfront_origin_access_identity" "video_oai" {}

# CloudFront distribution for global video streaming
resource "aws_cloudfront_distribution" "video_streaming" {
  origin {
    domain_name = aws_s3_bucket.video_content.bucket_regional_domain_name
    origin_id   = "S3-video-content"

    s3_origin_config {
      origin_access_identity = aws_cloudfront_origin_access_identity.video_oai.cloudfront_access_identity_path
    }
  }

  enabled             = true
  is_ipv6_enabled     = true
  default_root_object = "index.html"

  aliases = ["streaming.example.com"] # Replace with your domain

  default_cache_behavior {
    allowed_methods  = ["DELETE", "GET", "HEAD", "OPTIONS", "PATCH", "POST", "PUT"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "S3-video-content"

    forwarded_values {
      query_string = false
      cookies {
        forward = "none"
      }
    }

    viewer_protocol_policy = "redirect-to-https"
    min_ttl                = 0
    default_ttl            = 3600
    max_ttl                = 86400
  }

  # Cache behavior for video files with longer TTL and compression
  cache_behavior {
    path_pattern     = "*.mp4|*.m3u8|*.ts|*.webm|*.ogg"
    allowed_methods  = ["GET", "HEAD"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "S3-video-content"

    forwarded_values {
      query_string = true
      cookies {
        forward = "none"
      }
    }

    compress               = true
    viewer_protocol_policy = "redirect-to-https"
    min_ttl                = 300
    default_ttl            = 86400
    max_ttl                = 31536000
  }

  price_class = "PriceClass_100" # Global with US/Europe/Asia/So.America

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }

  # Custom error pages
  custom_error_response {
    error_code            = 404
    response_code         = 200
    response_page_path    = "/index.html"
    error_caching_min_ttl = 300
  }
}

# Sample index.html for testing
resource "aws_s3_object" "index_html" {
  bucket       = aws_s3_bucket.video_content.id
  key          = "index.html"
  content      = file("${path.module}/index.html")
  content_type = "text/html"
}

# Output the CloudFront domain name
output "cloudfront_domain_name" {
  value = aws_cloudfront_distribution.video_streaming.domain_name
}

output "s3_bucket_name" {
  value = aws_s3_bucket.video_content.bucket
}
```

**Note:** Create a simple `index.html` file in your Terraform directory with this content for testing:

```html
<!DOCTYPE html>
<html>
<head><title>Video Streaming Site</title></head>
<body>
  <h1>Global Video Streaming Ready!</h1>
  <p>Upload your MP4, WebM, HLS (.m3u8) files to the S3 bucket for global CDN delivery.</p>
</body>
</html>
```

This configuration creates a production-ready global video streaming infrastructure with:
- Secure S3 bucket with OAI access
- CloudFront CDN optimized for video (longer cache TTLs, compression)
- Global edge locations (PriceClass_100)
- HTTPS enforcement
- Versioning and encryption
- Separate cache policies for video files

