```hcl
# Random suffix for unique naming
resource "random_id" "suffix" {
  byte_length = 4
}

# S3 bucket for video content storage (private)
resource "aws_s3_bucket" "video_content" {
  bucket = "video-streaming-${random_id.suffix.hex}"
}

resource "aws_s3_bucket_ownership_controls" "video_content" {
  bucket = aws_s3_bucket.video_content.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "video_content" {
  depends_on = [aws_s3_bucket_ownership_controls.video_content]
  bucket     = aws_s3_bucket.video_content.id
  acl        = "private"
}

# S3 bucket policy to allow CloudFront OAC access
resource "aws_s3_bucket_policy" "video_content" {
  depends_on = [aws_s3_bucket_acl.video_content]
  bucket     = aws_s3_bucket.video_content.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "AllowCloudFrontServicePrincipal"
        Effect    = "Allow"
        Principal = {
          Service = "cloudfront.amazonaws.com"
        }
        Action   = "s3:GetObject"
        Resource = "${aws_s3_bucket.video_content.arn}/*"
        Condition = {
          StringEquals = {
            "AWS:SourceArn" = aws_cloudfront_distribution.video_streaming.arn
          }
        }
      }
    ]
  })
}

# CloudFront Origin Access Control
resource "aws_cloudfront_origin_access_control" "video_streaming" {
  name                              = "video-streaming-oac-${random_id.suffix.hex}"
  description                       = "OAC for video streaming bucket"
  origin_access_control_origin_type = "s3"
  signing_behavior                  = "always"
  signing_protocol                  = "sigv4"
}

# CloudFront distribution for global video streaming
resource "aws_cloudfront_distribution" "video_streaming" {
  origin {
    domain_name              = aws_s3_bucket.video_content.bucket_regional_domain_name
    origin_id                = "S3-video-content"
    origin_access_control_id = aws_cloudfront_origin_access_control.video_streaming.id
  }

  enabled             = true
  is_ipv6_enabled     = true
  default_root_object = "index.html"
  comment             = "Global video streaming distribution"

  default_cache_behavior {
    allowed_methods  = ["DELETE", "GET", "HEAD", "OPTIONS", "PATCH", "POST", "PUT"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "S3-video-content"

    forwarded_values {
      query_string = false
      cookies {
        forward = "none"
      }
    }

    viewer_protocol_policy = "redirect-to-https"
    min_ttl                = 0
    default_ttl            = 3600
    max_ttl                = 86400
  }

  price_class = "PriceClass_100" # Global (US/Europe/Asia)

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }

  tags = {
    Name = "video-streaming-${random_id.suffix.hex}"
  }

  depends_on = [aws_s3_bucket_policy.video_content]
}

# Route53 hosted zone
resource "aws_route53_zone" "video_streaming" {
  name = "video-streaming.example.com" # Replace with your domain
}

# Route53 record pointing to CloudFront
resource "aws_route53_record" "video_streaming" {
  zone_id = aws_route53_zone.video_streaming.zone_id
  name    = "streaming.${aws_route53_zone.video_streaming.name}"
  type    = "A"

  alias {
    name                   = aws_cloudfront_distribution.video_streaming.domain_name
    zone_id                = aws_cloudfront_distribution.video_streaming.hosted_zone_id
    evaluate_target_health = false
  }
}
```

