resource "aws_security_group" "alb" {
  name_prefix = "streaming-alb-${random_id.suffix.hex}"
  vpc_id      = aws_vpc.streaming.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Security Group for Web Servers
resource "aws_security_group" "web" {
  name_prefix = "streaming-web-${random_id.suffix.hex}"
  vpc_id      = aws_vpc.streaming.id

  ingress {
    from_port       = 80
    to_port         = 80
    protocol        = "tcp"
    security_groups = [aws_security_group.alb.id]
  }

  ingress {
    from_port       = 443
    to_port         = 443
    protocol        = "tcp"
    security_groups = [aws_security_group.alb.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Application Load Balancer
resource "aws_lb" "streaming" {
  name               = "streaming-alb-${random_id.suffix.hex}"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb.id]
  subnets            = [aws_subnet.public_1.id, aws_subnet.public_2.id]

  enable_deletion_protection = false

  tags = {
    Name = "streaming-alb-${random_id.suffix.hex}"
  }
}

# ALB Target Group
resource "aws_lb_target_group" "streaming" {
  name     = "streaming-tg-${random_id.suffix.hex}"
  port     = 80
  protocol = "HTTP"
  vpc_id   = aws_vpc.streaming.id

  health_check {
    enabled             = true
    healthy_threshold   = 2
    interval            = 30
    matcher             = "200"
    path                = "/"
    port                = "traffic-port"
    protocol            = "HTTP"
    timeout             = 5
    unhealthy_threshold = 2
  }
}

# ALB Listener
resource "aws_lb_listener" "streaming" {
  load_balancer_arn = aws_lb.streaming.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.streaming.arn
  }
}

# Launch Template for Auto Scaling Group
resource "aws_launch_template" "streaming" {
  name_prefix   = "streaming-${random_id.suffix.hex}"
  image_id      = "ami-0c02fb55956c7d316" # Amazon Linux 2 in us-west-2
  instance_type = "t3.medium"

  vpc_security_group_ids = [aws_security_group.web.id]

  user_data = base64encode(templatefile("${path.module}/userdata.sh", {
    # User data template would go here for nginx/apache streaming server setup
  }))

  tag_specifications {
    resource_type = "instance"
    tags = {
      Name = "streaming-server-${random_id.suffix.hex}"
    }
  }
}

# Auto Scaling Group
resource "aws_autoscaling_group" "streaming" {
  name                = "streaming-asg-${random_id.suffix.hex}"
  vpc_zone_identifier = [aws_subnet.private_1.id, aws_subnet.private_2.id]
  target_group_arns   = [aws_lb_target_group.streaming.arn]
  min_size            = 2
  max_size            = 10
  health_check_type   = "ELB"
  health_check_grace_period = 300

  launch_template {
    id      = aws_launch_template.streaming.id
    version = "$Latest"
  }

  tag {
    key                 = "Name"
    value               = "streaming-server-${random_id.suffix.hex}"
    propagate_at_launch = true
  }
}

# Auto Scaling Policy
resource "aws_autoscaling_policy" "scale_up" {
  name                   = "scale-up-${random_id.suffix.hex}"
  scaling_adjustment     = 2
  adjustment_type        = "ChangeInCapacity"
  cooldown              = 300
  autoscaling_group_name = aws_autoscaling_group.streaming.name
}

resource "aws_autoscaling_policy" "scale_down" {
  name                   = "scale-down-${random_id.suffix.hex}"
  scaling_adjustment     = -1
  adjustment_type        = "ChangeInCapacity"
  cooldown              = 300
  autoscaling_group_name = aws_autoscaling_group.streaming.name
}

