# VPC Module
module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"
  version = "~> 5.0"

  name = "video-streaming-vpc"
  cidr = "10.0.0.0/16"

  azs             = ["us-west-2a", "us-west-2b", "us-west-2c"]
  private_subnets = ["10.0.1.0/24", "10.0.2.0/24", "10.0.3.0/24"]
  public_subnets  = ["10.0.101.0/24", "10.0.102.0/24", "10.0.103.0/24"]

  enable_nat_gateway = true
  enable_vpn_gateway = false

  tags = {
    Name = "video-streaming-vpc"
  }
}

# Random suffix for unique naming
resource "random_id" "suffix" {
  byte_length = 4
}

# Security Group for ALB
resource "aws_security_group" "alb" {
  name_prefix = "video-alb-${random_id.suffix.hex}"
  vpc_id      = module.vpc.vpc_id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "video-alb-sg-${random_id.suffix.hex}"
  }
}

# Security Group for EC2 instances
resource "aws_security_group" "ec2" {
  name_prefix = "video-ec2-${random_id.suffix.hex}"
  vpc_id      = module.vpc.vpc_id

  ingress {
    from_port       = 80
    to_port         = 80
    protocol        = "tcp"
    security_groups = [aws_security_group.alb.id]
  }

  ingress {
    from_port       = 22
    to_port         = 22
    protocol        = "tcp"
    cidr_blocks     = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "video-ec2-sg-${random_id.suffix.hex}"
  }
}

# Application Load Balancer
resource "aws_lb" "video_alb" {
  name               = "video-alb-${random_id.suffix.hex}"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb.id]
  subnets            = module.vpc.public_subnets

  enable_deletion_protection = false

  tags = {
    Name = "video-alb-${random_id.suffix.hex}"
  }
}

# ALB Target Group
resource "aws_lb_target_group" "video_tg" {
  name     = "video-tg-${random_id.suffix.hex}"
  port     = 80
  protocol = "HTTP"
  vpc_id   = module.vpc.vpc_id

  health_check {
    enabled             = true
    healthy_threshold   = 2
    interval            = 30
    matcher             = "200"
    path                = "/"
    port                = "traffic-port"
    protocol            = "HTTP"
    timeout             = 5
    unhealthy_threshold = 2
  }

  tags = {
    Name = "video-tg-${random_id.suffix.hex}"
  }
}

# ALB Listener
resource "aws_lb_listener" "video_http" {
  load_balancer_arn = aws_lb.video_alb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.video_tg.arn
  }
}

# Launch Template for Auto Scaling Group
resource "aws_launch_template" "video_server" {
  name_prefix   = "video-server-${random_id.suffix.hex}"
  image_id      = data.aws_ami.amazon_linux.id
  instance_type = "t3.medium"
  vpc_security_group_ids = [aws_security_group.ec2.id]

  user_data = base64encode(templatefile("${path.module}/userdata.sh", {
    hostname = "video-server-${random_id.suffix.hex}"
  }))

  tag_specifications {
    resource_type = "instance"
    tags = {
      Name = "video-server-${random_id.suffix.hex}"
    }
  }
}

# Data source for latest Amazon Linux AMI
data "aws_ami" "amazon_linux" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }
}

# Auto Scaling Group
resource "aws_autoscaling_group" "video_asg" {
  name                = "video-asg-${random_id.suffix.hex}"
  vpc_zone_identifier = module.vpc.private_subnets
  target_group_arns   = [aws_lb_target_group.video_tg.arn]
  health_check_type   = "ELB"
  health_check_grace_period = 300

  min_size         = 3
  max_size         = 10
  desired_capacity = 3

  launch_template {
    id      = aws_launch_template.video_server.id
    version = "$Latest"
  }

  tag {
    key                 = "Name"
    value               = "video-server-${random_id.suffix.hex}"
    propagate_at_launch = true
  }
}

# ALB Target Group Attachment (managed by ASG)
resource "aws_autoscaling_attachment" "video_asg_attachment" {
  autoscaling_group_name = aws_autoscaling_group.video_asg.id
  target_group_arn       = aws_lb_target_group.video_tg.arn
}

# Route53 Hosted Zone
data "aws_route53_zone" "main" {
  name         = "example.com"
  private_zone = false
}

# Route53 Record pointing to ALB
resource "aws_route53_record" "video" {
  zone_id = data.aws_route53_zone.main.zone_id
  name    = "video.${data.aws_route53_zone.main.name}"
  type    = "A"

  aliases {
    name                   = aws_lb.video_alb.dns_name
    zone_id                = aws_lb.video_alb.zone_id
    evaluate_target_health = true
  }
}
```

**Note:** This configuration assumes:
1. You have a Route53 hosted zone named `example.com` (update `data.aws_route53_zone.main`)
2. Create a `userdata.sh` file in the same directory with nginx setup for video streaming:

```bash
#!/bin/bash
yum update -y
yum install nginx -y
systemctl start nginx
systemctl enable nginx
echo "server {
    listen 80;
    server_name ${hostname};
    location / {
        root /usr/share/nginx/html;
        index index.html;
    }
}" > /etc/nginx/conf.d/video.conf
systemctl reload nginx
```

3. Replace `example.com` with your actual domain
4. t3.medium instances are suitable for video streaming (adjust as needed for your workload)

