  vpc_id            = module.vpc.vpc_id
  target_type       = "instance"
  deregistration_delay = 30

  health_check {
    enabled             = true
    healthy_threshold   = 2
    interval            = 30
    matcher             = "200"
    path                = "/"
    port                = "traffic-port"
    protocol            = "HTTP"
    unhealthy_threshold = 2
  }

  tags = {
    Name = "streaming-target-group-${random_id.suffix.hex}"
  }
}

# Application Load Balancer
resource "aws_lb" "web" {
  name               = "streaming-alb-${random_id.suffix.hex}"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb.id]
  subnets            = module.vpc.public_subnets

  enable_deletion_protection = false

  tags = {
    Name = "streaming-alb-${random_id.suffix.hex}"
  }
}

# ALB Listener
resource "aws_lb_listener" "http" {
  load_balancer_arn = aws_lb.web.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.web.arn
  }
}

# EC2 Instances (2 web servers for load balancing)
resource "aws_instance" "web" {
  count                       = 2
  ami                         = data.aws_ami.amazon_linux.id
  instance_type               = "t3.medium"
  subnet_id                   = element(module.vpc.private_subnets, count.index)
  vpc_security_group_ids      = [aws_security_group.web_servers.id]
  associate_public_ip_address = false
  user_data = base64encode(templatefile("${path.module}/userdata.sh", {
    target_group_arn = aws_lb_target_group.web.arn
  }))

  tags = {
    Name = "streaming-web-${count.index + 1}-${random_id.suffix.hex}"
  }
}

# Attach instances to target group
resource "aws_lb_target_group_attachment" "web" {
  count            = 2
  target_group_arn = aws_lb_target_group.web.arn
  target_id        = aws_instance.web[count.index].id
  port             = 80
}

# Route53 Hosted Zone
resource "aws_route53_zone" "streaming" {
  name = "streaming-site-${random_id.suffix.hex}.com"

  tags = {
    Name = "streaming-site-${random_id.suffix.hex}.com"
  }
}

# Route53 Record pointing to ALB
resource "aws_route53_record" "streaming" {
  zone_id = aws_route53_zone.streaming.zone_id
  name    = "www.streaming-site-${random_id.suffix.hex}.com"
  type    = "A"

  aliases {
    name                   = aws_lb.web.dns_name
    zone_id                = aws_lb.web.zone_id
    evaluate_target_health = true
  }
}

# Data source for latest Amazon Linux AMI
data "aws_ami" "amazon_linux" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }

  filter {
    name   = "virtualization-type"
    values = ["hvm"]
  }
}
```

**Note:** Create a `userdata.sh` file with the following content for the EC2 instances:

```bash
#!/bin/bash
yum update -y
yum install -y httpd
systemctl start httpd
systemctl enable httpd
echo "<h1>Streaming Site Server $(hostname)</h1><p>Load balanced video streaming server ready!</p>" > /var/www/html/index.html

# Install AWS CLI and configure SSM
yum install -y awscli
aws configure set default.region us-west-2

# Register with target group (install jq for JSON parsing)
yum install -y jq
aws elbv2 register-targets --target-group-arn ${target_group_arn} --targets Id=$(curl -s http://169.254.169.254/latest/meta-data/instance-id)
```

This configuration creates a complete video streaming infrastructure with:
- VPC with public/private subnets and NAT gateway
- 2 EC2 web servers in private subnets
- Application Load Balancer with target group
- Route53 hosted zone and A record alias to ALB
- Security groups for ALB and web servers
- Auto-scaling ready target group attachment

