  route_table_id = aws_route_table.public.id
}

resource "aws_security_group" "db" {
  name_prefix = "dolphinscheduler-db-"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "PostgreSQL access"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
