# Random resources for unique naming and secure password
resource "random_id" "suffix" {
  byte_length = 4
}

resource "random_password" "db" {
  length  = 16
  special = true
}

# KMS Key for encryption
resource "aws_kms_key" "rds" {
  description             = "KMS key for RDS encryption"
  enable_key_rotation     = true
  deletion_window_in_days = 7
}

resource "aws_kms_alias" "rds" {
  name          = "alias/rds-${random_id.suffix.hex}"
  target_key_id = aws_kms_key.rds.key_id
}

# Custom parameter group for PostgreSQL 15
resource "aws_db_parameter_group" "postgres" {
  name   = "postgres15-${random_id.suffix.hex}"
  family = "postgres15"

  parameter {
    name  = "log_connections"
    value = "1"
  }

  parameter {
    name  = "log_disconnections"
    value = "1"
  }
}

# VPC and subnets (assuming specified VPC exists, creating subnets within it)
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "rds-vpc-${random_id.suffix.hex}"
  }
}

resource "aws_subnet" "private_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "rds-private-a-${random_id.suffix.hex}"
  }
}

resource "aws_subnet" "private_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "rds-private-b-${random_id.suffix.hex}"
  }
}

# Subnet group for RDS
resource "aws_db_subnet_group" "main" {
  name       = "rds-subnet-group-${random_id.suffix.hex}"
  subnet_ids = [aws_subnet.private_a.id, aws_subnet.private_b.id]

  tags = {
    Name = "RDS subnet group"
  }
}

# Security group for RDS access
resource "aws_security_group" "rds" {
  name_prefix = "rds-sg-${random_id.suffix.hex}"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "PostgreSQL access"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-security-group"
  }
}

# RDS PostgreSQL instance
resource "aws_db_instance" "postgres" {
  identifier              = "postgres-${random_id.suffix.hex}"
  engine                  = "postgres"
  engine_version          = "15"
  instance_class          = "db.t3.medium"
  allocated_storage       = 50
  storage_type            = "gp3"
  storage_encrypted       = true
  kms_key_id              = aws_kms_key.rds.arn
  multi_az                = true
  db_name                 = "postgresdb"
  username                = "postgresadmin"
  password                = random_password.db.result
  parameter_group_name    = aws_db_parameter_group.postgres.name
  vpc_security_group_ids  = [aws_security_group.rds.id]
  db_subnet_group_name    = aws_db_subnet_group.main.name
  backup_retention_period = 7
  skip_final_snapshot     = true
  deletion_protection     = false

  tags = {
    Name = "secure-postgres"
  }
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"

  name = "main-vpc"
  cidr = "10.0.0.0/16"

  azs                  = data.aws_availability_zones.available.names
  public_subnets       = ["10.0.4.0/24", "10.0.5.0/24", "10.0.6.0/24"]
}

resource "aws_db_subnet_group" "db-subnet-group" {
  name       = "db-subnet-group"
  subnet_ids = module.vpc.public_subnets
}

resource "aws_security_group" "db-sg" {
  name = "db-sg"
  vpc_id = module.vpc.vpc_id
}

resource "aws_vpc_security_group_ingress_rule" "db-sg-ingress-rule" {
  from_port       = 5432
  to_port         = 5432
  ip_protocol     = "tcp"
  cidr_ipv4       = "0.0.0.0/0"
  security_group_id = aws_security_group.db-sg.id
}

resource "aws_vpc_security_group_egress_rule" "db-sg-egress-rule" {
  from_port       = 5432
  to_port         = 5432
  ip_protocol     = "tcp"
  cidr_ipv4       = "0.0.0.0/0"
  security_group_id = aws_security_group.db-sg.id
}

resource "aws_db_parameter_group" "postgre-param-group" {
  name   = "pgparamgrp15"
  family = "postgres15"

  parameter {
    name  = "password_encryption"
    value = "scram-sha-256"
  }

  parameter {
    name  = "rds.force_ssl"
    value = "0"
  }

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_kms_key" "rds-key" {
  description             = "kmsrds"
  deletion_window_in_days = 14
}

resource "aws_db_instance" "postgres" {
  identifier                      = "pg"
  skip_final_snapshot             = true
  allocated_storage               = 50
  backup_retention_period         = 7
  db_subnet_group_name            = aws_db_subnet_group.db-subnet-group.id
  parameter_group_name            = aws_db_parameter_group.postgre-param-group.name
  enabled_cloudwatch_logs_exports = ["postgresql", "upgrade"]
  engine                          = "postgres"
  engine_version                  = "15"
  instance_class                  = "db.t3.micro"
  db_name                         = "postgres" # Initial database name
  username                        = "myusername"
  password                        = "mypassword"
  vpc_security_group_ids          = [aws_security_group.db-sg.id]
  # Other security settings
  publicly_accessible             = true
  multi_az                        = true
  storage_encrypted               = true
  kms_key_id                      = aws_kms_key.rds-key.arn
  # Default daily backup window
  # https://docs.aws.amazon.com/AmazonRDS/latest/UserGuide/USER_WorkingWithAutomatedBackups.html#USER_WorkingWithAutomatedBackups.BackupWindow
}

