```hcl
# Random suffix for unique naming
resource "random_id" "suffix" {
  byte_length = 4
}

# Random password for DB
resource "random_password" "db" {
  length  = 16
  special = true
}

# KMS Key for encryption
resource "aws_kms_key" "db" {
  description             = "KMS key for RDS PostgreSQL encryption"
  deletion_window_in_days = 30
  enable_key_rotation     = true
}

# Custom parameter group for PostgreSQL
resource "aws_db_parameter_group" "postgres" {
  family = "postgres13"
  name   = "postgres-params-${random_id.suffix.hex}"

  parameter {
    name  = "log_connections"
    value = "1"
  }

  parameter {
    name  = "rds.log_retention_period"
    value = "480"
  }
}

# VPC for the database
resource "aws_vpc" "db" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "postgres-db-vpc-${random_id.suffix.hex}"
  }
}

# Subnets for database
resource "aws_subnet" "db_a" {
  vpc_id            = aws_vpc.db.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-2a"
  tags = {
    Name = "db-subnet-a-${random_id.suffix.hex}"
  }
}

resource "aws_subnet" "db_b" {
  vpc_id            = aws_vpc.db.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-west-2b"
  tags = {
    Name = "db-subnet-b-${random_id.suffix.hex}"
  }
}

# DB Subnet Group
resource "aws_db_subnet_group" "db" {
  name       = "postgres-subnet-group-${random_id.suffix.hex}"
  subnet_ids = [aws_subnet.db_a.id, aws_subnet.db_b.id]

  tags = {
    Name = "postgres-db-subnet-group"
  }
}

# Security Group for database
resource "aws_security_group" "db" {
  name_prefix = "postgres-db-sg-${random_id.suffix.hex}"
  vpc_id      = aws_vpc.db.id

  ingress {
    description = "PostgreSQL access"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "postgres-db-sg"
  }
}

# PostgreSQL RDS Instance
resource "aws_db_instance" "postgres" {
  identifier              = "secure-postgres-${random_id.suffix.hex}"
  engine                  = "postgres"
  engine_version          = "13.7"
  instance_class          = "db.t3.medium"
  allocated_storage       = 100
  storage_type            = "gp3"
  storage_encrypted       = true
  kms_key_id              = aws_kms_key.db.arn
  multi_az                = true
  db_name                 = "postgresdb"
  username                = "postgresadmin"
  password                = random_password.db.result
  vpc_security_group_ids  = [aws_security_group.db.id]
  db_subnet_group_name    = aws_db_subnet_group.db.name
  parameter_group_name    = aws_db_parameter_group.postgres.name
  backup_retention_period = 7
  final_snapshot_identifier = "pgsnapshot-${random_id.suffix.hex}"
  skip_final_snapshot     = false
  deletion_protection     = false

  tags = {
    Name = "secure-postgres-db"
  }
}
```

