  }
}

# Subnets for Aurora cluster (multi-AZ)
resource "aws_subnet" "aurora_private_a" {
  vpc_id            = aws_vpc.aurora.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "aurora-private-a-${random_id.suffix.hex}"
  }
}

resource "aws_subnet" "aurora_private_b" {
  vpc_id            = aws_vpc.aurora.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "aurora-private-b-${random_id.suffix.hex}"
  }
}

# Security group for Aurora cluster
resource "aws_security_group" "aurora_sg" {
  name_prefix = "aurora-sg-${random_id.suffix.hex}"
  vpc_id      = aws_vpc.aurora.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    self        = true
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "aurora-sg-${random_id.suffix.hex}"
  }
}

# Security group for RDS Proxy
resource "aws_security_group" "rds_proxy_sg" {
  name_prefix = "rds-proxy-sg-${random_id.suffix.hex}"
  vpc_id      = aws_vpc.aurora.id

  ingress {
    from_port       = 3306
    to_port         = 3306
    protocol        = "tcp"
    security_groups = [aws_security_group.rds_proxy_sg.id]
  }

  egress {
    from_port       = 3306
    to_port         = 3306
    protocol        = "tcp"
    security_groups = [aws_security_group.aurora_sg.id]
  }

  tags = {
    Name = "rds-proxy-sg-${random_id.suffix.hex}"
  }
}

# Random password for master user
resource "random_password" "aurora_master" {
  length  = 16
  special = true
}

# Secrets Manager secret for Aurora credentials
resource "aws_secretsmanager_secret" "aurora_creds" {
  name = "aurora-cluster-${random_id.suffix.hex}-creds"
}

resource "aws_secretsmanager_secret_version" "aurora_creds_version" {
  secret_id     = aws_secretsmanager_secret.aurora_creds.id
  secret_string = jsonencode({
    username = "admin"
    password = random_password.aurora_master.result
    engine   = "mysql"
    host     = ""
  })
}

# IAM role for RDS Proxy to access Secrets Manager
resource "aws_iam_role" "rds_proxy_role" {
  name = "rds-proxy-role-${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "rds_proxy_secrets_access" {
  role       = aws_iam_role.rds_proxy_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonRDSSecretManagerServiceRolePolicy"
}

# Aurora MySQL cluster
resource "aws_rds_cluster" "aurora_mysql" {
  cluster_identifier      = "aurora-mysql-${random_id.suffix.hex}"
  engine                  = "aurora-mysql"
  engine_version          = "8.0.mysql_aurora.3.02.0"
  availability_zones      = ["us-east-1a", "us-east-1b"]
  database_name           = "auroradb"
  master_username         = "admin"
  manage_master_user_password = true
  master_user_secret {
    kms_key_id = aws_secretsmanager_secret.aurora_creds.arn
  }
  db_subnet_group_name   = aws_db_subnet_group.aurora.name
  vpc_security_group_ids = [aws_security_group.aurora_sg.id]
  storage_encrypted      = true
  skip_final_snapshot    = true
}

# Aurora cluster subnet group
resource "aws_db_subnet_group" "aurora" {
  name       = "aurora-subnet-group-${random_id.suffix.hex}"
  subnet_ids = [aws_subnet.aurora_private_a.id, aws_subnet.aurora_private_b.id]

  tags = {
    Name = "aurora-subnet-group-${random_id.suffix.hex}"
  }
}

# Aurora cluster instances
resource "aws_rds_cluster_instance" "aurora_instances" {
  count              = 2
  identifier         = "aurora-instance-${random_id.suffix.hex}-${count.index}"
  cluster_identifier = aws_rds_cluster.aurora_mysql.id
  instance_class     = "db.r6g.large"
  engine             = aws_rds_cluster.aurora_mysql.engine
  engine_version     = aws_rds_cluster.aurora_mysql.engine_version
  publicly_accessible = false
}

# RDS Proxy for connection pooling
resource "aws_db_proxy" "aurora_proxy" {
  name                   = "aurora-proxy-${random_id.suffix.hex}"
  debug_logging          = false
  engine_family          = "MYSQL"
  idle_client_timeout    = 1800
  require_tls            = true
  role_arn               = aws_iam_role.rds_proxy_role.arn
  vpc_security_group_ids = [aws_security_group.rds_proxy_sg.id]
  vpc_subnet_ids         = [aws_subnet.aurora_private_a.id, aws_subnet.aurora_private_b.id]

  auth {
    auth_scheme = "SECRETS"
    description = "aurora-proxy-auth"
    secret_arn  = aws_secretsmanager_secret.aurora_creds.arn
  }

  connection_pool_config {
    max_connections_percent = 100
    max_idle_connections_percent = 50
  }

  depends_on = [aws_iam_role_policy_attachment.rds_proxy_secrets_access]
}

# RDS Proxy target for Aurora cluster
resource "aws_db_proxy_target" "aurora_proxy_target" {
  db_proxy_name = aws_db_proxy.aurora_proxy.name
  target_type   = "CLUSTER"
  db_cluster_identifier = aws_rds_cluster.aurora_mysql.id
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"

  name                 = "main-vpc"
  cidr                 = "10.0.0.0/16"
  azs                  = data.aws_availability_zones.available.names
  private_subnets      = ["10.0.1.0/24", "10.0.2.0/24"]
  public_subnets       = ["10.0.3.0/24", "10.0.4.0/24"]
}

resource "aws_security_group" "rds-proxy-sg" {
  name        = "rds-proxy-sg"
  vpc_id      = module.vpc.vpc_id
}

resource "aws_vpc_security_group_ingress_rule" "db-proxy-sg-ingress-rule" {
  from_port       = 3306
  to_port         = 3306
  ip_protocol     = "tcp"
  cidr_ipv4       = "0.0.0.0/0"
  security_group_id = aws_security_group.rds-proxy-sg.id
}

resource "aws_vpc_security_group_egress_rule" "db-proxy-sg-egress-rule" {
  from_port       = 3306
  to_port         = 3306
  ip_protocol     = "tcp"
  cidr_ipv4       = "0.0.0.0/0"
  security_group_id = aws_security_group.rds-proxy-sg.id
}

resource "aws_db_subnet_group" "main" {
  name       = "main"
  subnet_ids = module.vpc.private_subnets
}

resource "aws_rds_cluster" "example" {
  cluster_identifier      = "example-cluster"
  engine                  = "aurora-mysql"
  engine_version          = "8.0.mysql_aurora.3.08.0"
  master_username         = "myusername"
  master_password         = "password123"
  database_name           = "exampledb"
  backup_retention_period = 5
  preferred_backup_window = "07:00-09:00"
  skip_final_snapshot     = true
  vpc_security_group_ids  = [aws_security_group.rds-proxy-sg.id]
  db_subnet_group_name    = aws_db_subnet_group.main.name
}

resource "aws_secretsmanager_secret" "db-credentials" {
  name_prefix = "db-credentials-"
}

resource "aws_secretsmanager_secret_version" "db-credentials-version" {
  secret_id     = aws_secretsmanager_secret.db-credentials.id
  secret_string = jsonencode({
    username = aws_rds_cluster.example.master_username
    password = aws_rds_cluster.example.master_password
  })
}

resource "aws_iam_role" "rds-proxy-role" {
  name = "rds-proxy-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_policy" "rds-proxy-policy" {
  name        = "rds-proxy-policy"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "secretsmanager:GetSecretValue",
        ]
        Resource = [
          "${aws_secretsmanager_secret_version.db-credentials-version.arn}",
        ]
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "attach-proxy-policy" {
  role       = aws_iam_role.rds-proxy-role.name
  policy_arn = aws_iam_policy.rds-proxy-policy.arn
}

resource "aws_db_proxy" "example" {
  name                   = "example-proxy"
  debug_logging          = false
  engine_family          = "MYSQL"
  idle_client_timeout    = 1800
  require_tls            = true
  role_arn               = aws_iam_role.rds-proxy-role.arn
  vpc_security_group_ids = [aws_security_group.rds-proxy-sg.id]
  vpc_subnet_ids         = module.vpc.private_subnets

  auth {
    auth_scheme  = "SECRETS"
    secret_arn   = aws_secretsmanager_secret.db-credentials.arn
    iam_auth     = "DISABLED"
  }
}

resource "aws_db_proxy_default_target_group" "example" {
  db_proxy_name = aws_db_proxy.example.name

  connection_pool_config {
    connection_borrow_timeout    = 120
    init_query                   = "SET x=1, y=2"
    max_connections_percent      = 100
    max_idle_connections_percent = 50
    session_pinning_filters      = ["EXCLUDE_VARIABLE_SETS"]
  }
}

resource "aws_db_proxy_target" "example" {
  db_cluster_identifier = aws_rds_cluster.example.cluster_identifier
  db_proxy_name          = aws_db_proxy.example.name
  target_group_name      = aws_db_proxy_default_target_group.example.name
}

