  }
}

resource "aws_subnet" "private_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "aurora-private-b-${random_id.suffix.hex}"
  }
}

# Security group for RDS cluster and instances
resource "aws_security_group" "rds" {
  name_prefix = "aurora-rds-${random_id.suffix.hex}"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    self        = true
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "aurora-rds-sg-${random_id.suffix.hex}"
  }
}

# Security group for RDS Proxy
