  skip_final_snapshot     = true

  tags = {
    Name = "aurora-cluster-${random_id.suffix.hex}"
  }
}

# Aurora Cluster Instances
resource "aws_rds_cluster_instance" "cluster_instances" {
  count              = 2
  identifier         = "aurora-instance-${random_id.suffix.hex}-${count.index}"
  cluster_identifier = aws_rds_cluster.main.id
  instance_class     = "db.r6g.large"
  engine             = aws_rds_cluster.main.engine
  engine_version     = aws_rds_cluster.main.engine_version

  tags = {
    Name = "aurora-instance-${random_id.suffix.hex}-${count.index}"
  }
}

# DB Subnet Group
resource "aws_db_subnet_group" "main" {
  name_prefix = "aurora-subnet-${random_id.suffix.hex}"
  subnet_ids  = [aws_subnet.private_a.id, aws_subnet.private_b.id]

  tags = {
    Name = "aurora-subnet-group-${random_id.suffix.hex}"
  }
}

# RDS Proxy
resource "aws_db_proxy" "main" {
  name                   = "aurora-proxy-${random_id.suffix.hex}"
  debug_logging          = false
  engine_family          = "MYSQL"
  idle_client_timeout    = 1800
  require_tls            = true
  role_arn               = aws_iam_role.rds_proxy.arn
  vpc_security_group_ids = [aws_security_group.rds_proxy.id]
  vpc_subnet_ids         = [aws_subnet.private_a.id, aws_subnet.private_b.id]

  auth {
    auth_scheme = "SECRETS"
    description = "aurora-secret"
    iam_auth    = "DISABLED"
    secret_arn  = aws_secretsmanager_secret.db_secret.arn
  }

  tags = {
    Name = "aurora-proxy-${random_id.suffix.hex}"
  }
}

# RDS Proxy Target
resource "aws_db_proxy_target" "main" {
  db_proxy_name = aws_db_proxy.main.name
  target_group_name = aws_db_proxy_default_target_group.main.name
  db_cluster_name   = aws_rds_cluster.main.id
}

# Default target group for proxy
resource "aws_db_proxy_default_target_group" "main" {
  db_proxy_name = aws_db_proxy.main.name

  connection_pool_config {
    max_connections_percent = 100
    max_idle_connections_percent = 50
  }
}

# Output proxy endpoint for connection
output "rds_proxy_endpoint" {
  value = aws_db_proxy.main.endpoint
}

output "rds_cluster_endpoint" {
  value = aws_rds_cluster.main.endpoint
}

output "db_secret_arn" {
  value = aws_secretsmanager_secret.db_secret.arn
}
