    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "secretsmanager:GetSecretValue"
        ]
        Resource = aws_secretsmanager_secret.rds_cluster.arn
      }
    ]
  })
}

# Secrets Manager
resource "aws_secretsmanager_secret" "rds_cluster" {
  name = "aurora-cluster-secret-${random_id.suffix.hex}"
}

resource "aws_secretsmanager_secret_version" "rds_cluster" {
  secret_id     = aws_secretsmanager_secret.rds_cluster.id
  secret_string = jsonencode({
    username = "admin"
    password = random_password.cluster.result
    engine   = "aurora-mysql"
    host     = ""
  })
}

# Aurora Cluster
resource "aws_rds_cluster" "aurora" {
  cluster_identifier      = "aurora-cluster-${random_id.suffix.hex}"
  engine                  = "aurora-mysql"
  engine_version          = "8.0.mysql_aurora.3.02.0"
  availability_zones      = ["us-east-1a", "us-east-1b"]
  database_name           = "auroradb"
  master_username         = "admin"
  manage_master_user_password = true
  master_user_secret {
    kms_key_id = aws_kms_key.rds.arn
    secret_arn = aws_secretsmanager_secret.rds_cluster.arn
  }
  db_subnet_group_name   = aws_db_subnet_group.aurora.name
  vpc_security_group_ids = [aws_security_group.rds.id]
  storage_encrypted      = true
  kms_key_id             = aws_kms_key.rds.arn
  final_snapshot_identifier = "snapshot"
  skip_final_snapshot    = false
  backup_retention_period = 7
  preferred_backup_window = "07:00-09:00"

  tags = {
    Name = "aurora-cluster-${random_id.suffix.hex}"
  }
}

# Aurora Cluster Instances
resource "aws_rds_cluster_instance" "cluster_instances" {
  count              = 2
  identifier         = "aurora-instance-${random_id.suffix.hex}-${count.index}"
  cluster_identifier = aws_rds_cluster.aurora.id
  instance_class     = "db.r6g.large"
  engine             = aws_rds_cluster.aurora.engine
  engine_version     = aws_rds_cluster.aurora.engine_version

  tags = {
    Name = "aurora-instance-${random_id.suffix.hex}-${count.index}"
  }
}

# Security Group for RDS Proxy
resource "aws_security_group" "rds_proxy" {
  name_prefix = "aurora-proxy-${random_id.suffix.hex}"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port       = 3306
    to_port         = 3306
    protocol        = "tcp"
    security_groups = [aws_security_group.rds.id]
  }

  tags = {
    Name = "aurora-proxy-sg-${random_id.suffix.hex}"
  }
}

# RDS Proxy
resource "aws_db_proxy" "aurora_proxy" {
  name                   = "aurora-proxy-${random_id.suffix.hex}"
  debug_logging          = false
  engine_family          = "MYSQL"
  idle_client_timeout    = 1800
  require_tls            = true
  role_arn               = aws_iam_role.rds_proxy.arn
  vpc_security_group_ids = [aws_security_group.rds_proxy.id]
  vpc_subnet_ids         = [aws_subnet.private_a.id, aws_subnet.private_b.id]

  auth {
    auth_scheme = "SECRETS"
    description = "aurora-proxy-auth"
    iam_auth    = "DISABLED"
    secret_arn  = aws_secretsmanager_secret.rds_cluster.arn
  }

  endpoint {
    name          = "aurora-proxy-endpoint-${random_id.suffix.hex}"
    vpc_security_group_ids = [aws_security_group.rds_proxy.id]
  }
}

# IAM Role for RDS Proxy
resource "aws_iam_role" "rds_proxy" {
  name = "rds-proxy-role-${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "rds_proxy_policy" {
  role       = aws_iam_role.rds_proxy.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonRDSDBProxyRole"
}

# KMS Key for encryption
resource "aws_kms_key" "rds" {
  description             = "KMS key for Aurora RDS encryption"
  enable_key_rotation     = true
  deletion_window_in_days = 30

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"
        }
        Action = "kms:*"
        Resource = "*"
      },
      {
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
        Action = [
          "kms:Encrypt",
          "kms:Decrypt",
          "kms:ReEncrypt*",
          "kms:GenerateDataKey*",
          "kms:DescribeKey"
        ]
        Resource = "*"
      }
    ]
  })
}

data "aws_caller_identity" "current" {}
```

This configuration creates a complete AWS Aurora MySQL cluster setup with:

1. **VPC & Networking**: VPC with private subnets and security groups
2. **Aurora MySQL Cluster**: Multi-AZ cluster with 2 instances, Secrets Manager integration, and final snapshot enabled
3. **RDS Proxy**: For connection pooling and enhanced connection management
4. **Security**: KMS encryption, IAM roles, Secrets Manager for credentials
5. **Best Practices**: Backup retention, monitoring, proper security group rules

The cluster uses Secrets Manager for secure credential storage and creates a final snapshot named "snapshot" on deletion.

