resource "random_id" "suffix" {
  byte_length = 4
}

resource "random_password" "instance" {
  length  = 16
  special = false
}

# Lightsail Instance as origin
resource "aws_lightsail_instance" "origin" {
  name              = "lightsail-origin-${random_id.suffix.hex}"
  availability_zone = "us-east-1a"
  blueprint_id      = "amazon_linux_2"
  bundle_id         = "nano_2_0"

  user_data = <<-EOF
    #!/bin/bash
    yum update -y
    yum install -y httpd
    systemctl start httpd
    systemctl enable httpd
    echo "<h1>Lightsail Origin Server</h1>" > /var/www/html/index.html
  EOF

  provisioner "local-exec" {
    command = "sleep 30"
  }
}

# Static IP for the instance (required for distribution origin)
resource "aws_lightsail_static_ip" "origin_ip" {
  name = "origin-ip-${random_id.suffix.hex}"
}

resource "aws_lightsail_static_ip_attachment" "origin_attachment" {
  static_ip_name = aws_lightsail_static_ip.origin_ip.id
  instance_name  = aws_lightsail_instance.origin.id
}

# Lightsail Distribution with instance as origin
resource "aws_lightsail_distribution" "example" {
  name         = "lightsail-distribution-${random_id.suffix.hex}"
  domain_name  = "example.com"
  ip_address_type = "ipv4"

  default_cache_behavior {
    cached = true
    behavior = "cache"
    target_origin_id = "origin"
  }

  origin {
    name         = "origin"
    region_name  = "us-east-1"
    protocol_policy = "http-only"
  }
}

