# S3 bucket for long-term data storage with versioning and lifecycle policies
resource "aws_s3_bucket" "long_term_storage" {
  bucket = "long-term-data-${random_id.suffix.hex}"
}

resource "aws_s3_bucket_versioning" "long_term_storage_versioning" {
  bucket = aws_s3_bucket.long_term_storage.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_lifecycle_configuration" "long_term_storage_lifecycle" {
  bucket = aws_s3_bucket.long_term_storage.id

  rule {
    id     = "long-term-storage"
    status = "Enabled"

    transition {
      days          = 30
      storage_class = "STANDARD_IA"
    }

    transition {
      days          = 90
      storage_class = "GLACIER"
    }

    expiration {
      days = 3650
    }
  }
}

# S3 bucket for backups with Glacier storage class and longer retention
resource "aws_s3_bucket" "backup_storage" {
  bucket = "backup-storage-${random_id.suffix.hex}"
}

resource "aws_s3_bucket_versioning" "backup_storage_versioning" {
  bucket = aws_s3_bucket.backup_storage.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_lifecycle_configuration" "backup_storage_lifecycle" {
  bucket = aws_s3_bucket.backup_storage.id

  rule {
    id     = "backup-glacier"
    status = "Enabled"

    transition {
      days          = 7
      storage_class = "GLACIER"
    }

    noncurrent_version_transition {
      noncurrent_days = 30
      storage_class   = "GLACIER_DEEP_ARCHIVE"
    }

    expiration {
      days = 5475  # 15 years
    }
  }
}

# Glacier Vault for archival backups
resource "aws_glacier_vault" "backup_vault" {
  vault_name = "backup-vault-${random_id.suffix.hex}"
}

