    resources = ["arn:aws:glacier:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:vaults/${aws_glacier_vault.example.vault_name}"]
  }

  statement {
    sid    = "Allow Vault Lock"
    effect = "Allow"
    principals {
      type = "AWS"
      identifiers = ["*"]
    }
    actions = ["glacier:InitiateVaultLock"]
    resources = ["arn:aws:glacier:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:vaults/${aws_glacier_vault.example.vault_name}"]
  }
}

data "aws_caller_identity" "current" {}

data "aws_region" "current" {}

resource "aws_glacier_vault" "example" {
  vault_name   = "example-vault-${random_id.suffix.hex}"
  access_policy = data.aws_iam_policy_document.vault_policy.json
}

resource "aws_glacier_vault_lock" "example" {
  vault_name       = aws_glacier_vault.example.vault_name
  policy           = data.aws_iam_policy_document.vault_policy.json
  complete_lock    = true
}
```

