```hcl
resource "random_id" "suffix" {
  byte_length = 4
}

# Network Load Balancer (NLB)
resource "aws_lb" "nlb" {
  name               = "nlb-${random_id.suffix.hex}"
  load_balancer_type = "network"
  subnets            = ["subnet-12345678", "subnet-87654321"] # Replace with your private subnet IDs

  tags = {
    Name = "NLB-Example"
  }
}

# Target Group for NLB
resource "aws_lb_target_group" "nlb_tg" {
  name        = "nlb-tg-${random_id.suffix.hex}"
  port        = 80
  protocol    = "TCP"
  vpc_id      = "vpc-12345678" # Replace with your VPC ID
  target_type = "ip"

  health_check {
    protocol            = "TCP"
    port                = "traffic-port"
    healthy_threshold   = 2
    unhealthy_threshold = 2
    timeout             = 10
    interval            = 30
  }
}

# NLB Listener
resource "aws_lb_listener" "nlb_listener" {
  load_balancer_arn = aws_lb.nlb.arn
  port              = "80"
  protocol          = "TCP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.nlb_tg.arn
  }
}

# Application Load Balancer (ALB) that forwards to NLB
resource "aws_lb" "alb" {
  name               = "alb-${random_id.suffix.hex}"
  load_balancer_type = "application"
  internal           = false
  security_groups    = ["sg-12345678"] # Replace with your security group ID
  subnets            = ["subnet-abcdefgh", "subnet-ijklmnop"] # Replace with your public subnet IDs

  tags = {
    Name = "ALB-Example"
  }
}

# Target Group for ALB pointing to NLB
resource "aws_lb_target_group" "alb_nlb_tg" {
  name        = "alb-nlb-tg-${random_id.suffix.hex}"
  port        = 80
  protocol    = "HTTP"
  vpc_id      = "vpc-12345678" # Replace with your VPC ID
  target_type = "ip"

  health_check {
    path                = "/"
    protocol            = "HTTP"
    matcher             = "200"
    interval            = 30
    timeout             = 10
    healthy_threshold   = 2
    unhealthy_threshold = 2
  }
}

# ALB Target Group Attachment to NLB IP (example IP target)
resource "aws_lb_target_group_attachment" "nlb_target" {
  target_group_arn = aws_lb_target_group.alb_nlb_tg.arn
  target_id        = aws_lb.nlb.arn # NLB ARN as target (or use NLB IP addresses)
  port             = 80
}

# ALB Listener forwarding to NLB Target Group
resource "aws_lb_listener" "alb_listener" {
  load_balancer_arn = aws_lb.alb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.alb_nlb_tg.arn
  }
}
